import type { Drill } from "./types";

// Lawyer / mid drills, keyed by module slug — 25 per module.
// Senior associate / counsel managing matters: client counseling, settlement
// recommendations, opposing counsel, supervising juniors, advising business
// teams, managing partner expectations. Merged into course.ts.
export const LAWYER_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-law-mid-01","level":"mid","profession":"lawyer","title":"The settlement recommendation that hides the number","scenario":"After mediation, you believe the client should accept the $450K settlement offer rather than push to trial. Your draft email to the GC opens with three paragraphs recounting the mediation before your recommendation appears.","task":"Write a 2-3 sentence email opening that leads with the recommendation and the number.","tips":["Sentence one: accept, and at what number.","The mediation recap is support — move it below.","A GC forwards the first line to the CFO; write it for that."],"focus":["structure","clarity"],"placeholder":"We recommend accepting the $450K offer."},
    {"id":"lead-law-mid-02","level":"mid","profession":"lawyer","title":"The partner hallway question","scenario":"The relationship partner stops you: \"Where are we on Meridian?\" The honest headline is that discovery closes Friday and you're on track, with one open dispute over a custodian. Your instinct is to start with the custodian saga.","task":"Give a spoken two-sentence answer that leads with the overall status.","tips":["Headline first: on track, discovery closes Friday.","The one exception comes second, sized honestly.","Partners triage on the first sentence — earn the next one."],"focus":["clarity","concision"],"placeholder":"On track — discovery closes Friday. One open issue:"},
    {"id":"lead-law-mid-03","level":"mid","profession":"lawyer","title":"The advice memo that saves the answer for page four","scenario":"The client's COO asked one question: can they terminate the supplier agreement for the missed deliveries? The answer is yes, with 30 days' notice. Your draft memo walks through the contract history before answering.","task":"Write the memo's opening 2 sentences so the answer comes first.","tips":["Answer the question asked in sentence one: yes, with 30 days' notice.","Conditions and reasoning follow, clearly labeled.","Busy executives read the first line and skim the rest."],"focus":["structure","clarity"],"placeholder":"Yes — you can terminate on 30 days' written notice."},
    {"id":"lead-law-mid-04","level":"mid","profession":"lawyer","title":"Breaking the bad ruling","scenario":"The court denied your client's motion to dismiss this morning. The case proceeds to discovery, which the client hoped to avoid. Your draft email eases in with how hard the team argued before stating the outcome.","task":"Write a 3-sentence email that states the outcome in the first sentence.","tips":["Bad news first, plainly: the motion was denied.","Then what it means: discovery proceeds, and roughly what that costs.","Close with the next step and when you'll discuss options."],"focus":["clarity","impact"],"placeholder":"The court denied our motion to dismiss this morning."},
    {"id":"lead-law-mid-05","level":"mid","profession":"lawyer","title":"Relaying the counteroffer","scenario":"Opposing counsel just countered at $1.2M against your client's $800K offer, dropping their demand from $2M. You need to email the client tonight. Your draft narrates the whole call before the number appears.","task":"Write an email opening that leads with the counteroffer and your one-line read on it.","tips":["First sentence: they countered at $1.2M, down from $2M.","Your read is the second sentence: real movement or posturing?","The call narrative is background — keep it short and below."],"focus":["structure","precision"]},
    {"id":"lead-law-mid-06","level":"mid","profession":"lawyer","title":"Feedback headline for the junior's draft","scenario":"A junior associate sent you a draft motion. The writing is fine, but the draft misses the strongest argument — the statute of limitations defense. Your comments so far are twenty small edits with the big issue mentioned last.","task":"Write the first 2 sentences of your feedback so the one big fix leads.","tips":["Name the most important change first: add the limitations argument.","Small edits are a list below, not the headline.","A junior acts on what you say first."],"focus":["clarity","impact"],"placeholder":"One big change before anything else: the draft needs the statute-of-limitations argument."},
    {"id":"lead-law-mid-07","level":"mid","profession":"lawyer","title":"The budget overrun heads-up","scenario":"The document review ballooned and the matter will run $60K over the $200K estimate you gave the partner. You need to tell her before the client sees the bill. Your draft opens with a history of why review expanded.","task":"Write a 2-3 sentence message that leads with the new number.","tips":["Lead with the revised total: $260K, not $200K.","One sentence on the driver, one on your proposed fix.","Partners forgive overruns flagged early; they don't forgive surprises."],"focus":["clarity","impact"],"placeholder":"Meridian will run about $260K — $60K over the estimate."},
    {"id":"lead-law-mid-08","level":"mid","profession":"lawyer","title":"The document ask with a hard deadline","scenario":"Discovery responses are due in ten days and the client's operations team still hasn't produced the maintenance logs you requested twice. You're drafting a third email that again explains the litigation background first.","task":"Write an email that puts the ask and the deadline in the first sentence.","tips":["Sentence one: what you need, from whom, by when.","Say what happens if the date slips — a court deadline, not a preference.","Name a single owner, not 'the team.'"],"focus":["clarity","impact"],"placeholder":"I need the maintenance logs from your team by Friday, June 12 —"},
    {"id":"lead-law-mid-09","level":"mid","profession":"lawyer","title":"The 20-second voicemail","scenario":"The court moved the preliminary injunction hearing from next Thursday to this Friday — four days from now. You're calling the client's GC, who is traveling. You tend to open voicemails with pleasantries and context.","task":"Script a voicemail of 3 sentences or fewer that leads with the change and the action needed.","tips":["First sentence: hearing moved to this Friday.","Second: what you need from them and by when.","Say your callback number slowly, once, at the end."],"focus":["concision","clarity"]},
    {"id":"lead-law-mid-10","level":"mid","profession":"lawyer","title":"The yes/no before signing","scenario":"The client's CEO emails at 6pm: \"Legal — anything stopping us from signing the distribution agreement tomorrow?\" There isn't; your two remaining comments are cosmetic. Your draft reply explains both comments before saying so.","task":"Write a reply that answers the question in the first three words.","tips":["Lead with the verdict: nothing stops signing.","Cosmetic comments get one sentence, framed as non-blocking.","Don't make a CEO parse caveats to find a yes."],"focus":["concision","clarity"],"placeholder":"No — you're clear to sign tomorrow."},
    {"id":"lead-law-mid-11","level":"mid","profession":"lawyer","title":"One line for the board deck","scenario":"The GC asks you for a single sentence on the patent litigation for the board pack. You know the case cold: fact discovery done, exposure narrowed to $2-4M, trial in Q2. Your first draft is five lines of procedural history.","task":"Write the one board-ready sentence that carries the point.","tips":["Lead with what the board cares about: exposure range and timing.","Procedural posture only earns words if it changes the risk.","One sentence means one sentence."],"focus":["concision","audience"],"placeholder":"Exposure on the patent case has narrowed to $2-4M, with trial expected in Q2."},
    {"id":"lead-law-mid-12","level":"mid","profession":"lawyer","title":"The clause question from sales","scenario":"The client's sales director asks whether they can agree to a customer's request for unlimited liability on data breaches. Your answer is no — cap it at 2x fees, which is your playbook fallback. Your draft explains liability theory first.","task":"Write a 2-3 sentence reply that leads with the answer and the fallback.","tips":["First sentence: no, and here's what you can offer instead.","Give sales the words they can take back to the customer.","Theory only if they ask."],"focus":["clarity","audience"],"placeholder":"No — don't agree to unlimited liability. Offer a 2x-fees cap instead."},
    {"id":"lead-law-mid-13","level":"mid","profession":"lawyer","title":"The regulator letter","scenario":"Your client received an information request from the state consumer-protection office with a 21-day response deadline. It's serious but routine. Your draft email to the client opens by describing the agency and its powers.","task":"Write an opening that leads with what arrived and the single most important action.","tips":["Sentence one: what arrived and the deadline it carries.","Sentence two: the first action — preserve documents, route all contact through you.","Calm and specific beats thorough and slow."],"focus":["clarity","impact"]},
    {"id":"lead-law-mid-14","level":"mid","profession":"lawyer","title":"The weekly matter email","scenario":"Your Friday update to the supervising partner covers the Hartwell matter. The real news: opposing counsel signaled openness to mediation for the first time. Your draft buries that under routine discovery status.","task":"Write the first 2 sentences of the update so the development leads.","tips":["Lead with what changed this week, not what continued.","Routine status becomes three short bullets below.","If nothing changed, say that in sentence one — that's also news."],"focus":["structure","concision"],"placeholder":"Development this week: opposing counsel raised mediation for the first time."},
    {"id":"lead-law-mid-15","level":"mid","profession":"lawyer","title":"The mediator's proposal","scenario":"The mediator has made a mediator's proposal: $700K, take it or leave it by Monday, both sides answering blind. You think the client should accept. Your draft email walks through the day's negotiation rounds first.","task":"Write a 2-3 sentence opening that leads with the proposal and your recommendation.","tips":["First sentence: the proposal, the deadline, and the blind-answer mechanic.","Second: your recommendation, stated as a recommendation.","Rounds and drama go in a short paragraph below."],"focus":["structure","clarity"],"placeholder":"The mediator proposed $700K, answer by Monday — we recommend accepting."},
    {"id":"lead-law-mid-16","level":"mid","profession":"lawyer","title":"The conflict flag","scenario":"Running intake on a new matter, you found the prospective adverse party is a subsidiary of an existing firm client. The partner needs to know before tomorrow's pitch call. Your draft explains how you discovered it first.","task":"Write a 2-sentence message that leads with the conflict and the decision it forces.","tips":["Sentence one: the conflict, named plainly.","Sentence two: the decision needed and by when — the pitch is tomorrow.","How you found it matters less than what it blocks."],"focus":["clarity","impact"],"placeholder":"We have a conflict on the Aldrin pitch: the adverse party is a Corvex subsidiary."},
    {"id":"lead-law-mid-17","level":"mid","profession":"lawyer","title":"The weak expert report","scenario":"You've reviewed the damages expert's draft report and the conclusion is unsupported — his lost-profits model ignores the client's own forecasts. The partner picked this expert. Your draft message reviews the report section by section.","task":"Write an opening that states your conclusion about the report first.","tips":["Lead with the verdict: the report won't survive a challenge as drafted.","Name the single biggest gap, then offer the fix.","Deference delays the conversation the partner needs to have."],"focus":["clarity","impact"]},
    {"id":"lead-law-mid-18","level":"mid","profession":"lawyer","title":"The staffing ask","scenario":"Depositions and a motion deadline now overlap, and you can't cover both alone. You need the partner to approve adding a second associate for three weeks. Your draft opens with an apology and the full calendar.","task":"Write a message that leads with the specific ask.","tips":["Sentence one: the ask — one associate, three weeks, starting Monday.","One sentence of why: two workstreams, one you.","Offer the alternative you'd cut if the answer is no."],"focus":["clarity","concision"],"placeholder":"I need a second associate on Hartwell for three weeks starting Monday."},
    {"id":"lead-law-mid-19","level":"mid","profession":"lawyer","title":"The extension request from the other side","scenario":"Opposing counsel emailed asking for a two-week extension on their discovery responses. You'd agree — you'll want the same courtesy later — but with a condition: the deposition dates hold. Your draft reply meanders through scheduling history.","task":"Write a reply whose first sentence gives your answer and the condition.","tips":["Lead with the answer: agreed, on one condition.","State the condition precisely — dates, not vibes.","Courteous and short reads as confident."],"focus":["clarity","precision"],"placeholder":"We'll agree to the two weeks, provided the deposition dates hold."},
    {"id":"lead-law-mid-20","level":"mid","profession":"lawyer","title":"The research answer","scenario":"The partner asked you to find out whether the non-solicitation clause is enforceable in the employee's new state. Answer: mostly yes, but the two-year term likely gets trimmed to one. Your draft summarizes six cases before saying so.","task":"Write the first 2 sentences of your reply so the answer leads and the cases support.","tips":["Answer first: enforceable, but expect the term cut to one year.","Cite the strongest authority in sentence two, not all six.","Partners want the answer; the memo can hold the trail."],"focus":["structure","clarity"],"placeholder":"Short answer: enforceable, but courts there trim two-year terms to one."},
    {"id":"lead-law-mid-21","level":"mid","profession":"lawyer","title":"The deposition debrief","scenario":"You defended the client's operations VP in deposition today. Headline: she held up well, and the other side got nothing new on the key liability theory. Your debrief email to the GC starts with a chronological account of the seven hours.","task":"Write a 2-sentence debrief opening that leads with the takeaway.","tips":["Lead with the verdict on the day: held up well, no new ground for them.","Name the one exchange worth flagging, if any.","Chronology is an attachment, not an opening."],"focus":["clarity","concision"]},
    {"id":"lead-law-mid-22","level":"mid","profession":"lawyer","title":"Reassigning the junior","scenario":"You need the junior associate to drop the contract summaries and spend today on deposition exhibits instead — the priority changed this morning. Your draft message explains the whole strategic backstory before the instruction.","task":"Write a short message that leads with the new instruction.","tips":["Sentence one: stop X, start Y, due when.","One sentence of why — enough to act intelligently, not a briefing.","Invite one clarifying question, then let them run."],"focus":["clarity","concision"],"placeholder":"Priority change: park the contract summaries and pull the deposition exhibits today."},
    {"id":"lead-law-mid-23","level":"mid","profession":"lawyer","title":"The client alert headline","scenario":"A new state privacy law takes effect in 90 days and your firm is sending a client alert you're drafting. The point clients need: if they collect consumer data in the state, they need a rights-request process by October 1. Your draft opens with the law's legislative history.","task":"Write the alert's first sentence so an affected client knows immediately it applies to them.","tips":["Lead with who is affected and what they must do by when.","Legislative history is for footnotes.","A reader should self-select in or out by line two."],"focus":["audience","impact"],"placeholder":"If you collect consumer data in Colorado, you need a rights-request process by October 1."},
    {"id":"lead-law-mid-24","level":"mid","profession":"lawyer","title":"The fee question answered straight","scenario":"The client's CFO emailed questioning why last month's bill jumped 40%. The real answer: the emergency injunction work they authorized. Your draft opens with a defense of the firm's rates in general.","task":"Write a reply whose first sentence answers the actual question.","tips":["Lead with the cause: the injunction work drove the increase.","Tie it to their authorization — date and decision.","Then offer the forward look: next month returns to baseline."],"focus":["clarity","precision"],"placeholder":"The jump is the emergency injunction work you authorized on May 6."},
    {"id":"lead-law-mid-25","level":"mid","profession":"lawyer","title":"The two-option decision email","scenario":"The client must choose by Wednesday: accept the landlord's final renewal terms or start relocation planning. You have a view — accept, the market moved against them. Your draft lays out both options exhaustively before hinting at a preference.","task":"Write an email opening that leads with the decision, the deadline, and your recommendation.","tips":["Sentence one: decision needed by Wednesday, and what you recommend.","Then the two options in two tight lines each.","A recommendation up front doesn't remove their choice — it frames it."],"focus":["structure","impact"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-law-mid-01","level":"mid","profession":"lawyer","title":"Summary judgment, explained to a founder","scenario":"The court denied the other side's motion for summary judgment — good news. Your client is a first-time founder who has never been in litigation. Your instinct is to write \"the court found genuine issues of material fact precluding judgment as a matter of law.\"","task":"Write a 2-3 sentence explanation the founder actually understands, including what happens next.","tips":["Translate the procedure into the stake: the case survives and heads toward trial or settlement.","Say whether this is good or bad for them — they can't tell.","One plain sentence on what happens next and when."],"focus":["audience","clarity"],"placeholder":"Good news: the judge refused to throw out our claims, which means"},
    {"id":"audience-law-mid-02","level":"mid","profession":"lawyer","title":"The indemnity cap for the sales team","scenario":"The client's sales team keeps agreeing to uncapped indemnities to close deals faster. You're writing two paragraphs for their playbook explaining why the cap matters. Your draft cites case law and defines 'consequential damages.'","task":"Rewrite the explanation in 3-4 sentences framed around what salespeople risk and what they can say to customers.","tips":["Their stake: one bad clause can cost more than the whole deal is worth.","Give them the customer-facing line, not the doctrine.","Name the escalation path when a customer pushes back."],"focus":["audience","impact"]},
    {"id":"audience-law-mid-03","level":"mid","profession":"lawyer","title":"One update, pick your reader","scenario":"You're updating the client on the licensing dispute. The GC wants procedural detail; the CEO, who is cc'd, wants to know if the product launch is at risk. You've been writing one email that serves neither well.","task":"Choose the CEO as the primary reader and write the 2-3 sentence version for her.","tips":["One primary audience per message — the GC can get detail in a separate note.","Lead with the launch question, because that's her question.","Keep procedure to one clause, if it appears at all."],"focus":["audience","structure"],"placeholder":"The dispute does not block the September launch."},
    {"id":"audience-law-mid-04","level":"mid","profession":"lawyer","title":"Privilege, explained before the interviews","scenario":"You're about to interview six client employees for an internal investigation. You need to give the standard explanation that you represent the company, not them, and what that means for confidentiality. The script you inherited is a paragraph of legalese.","task":"Write a 3-4 sentence plain-language version you could say aloud to a warehouse supervisor.","tips":["Say plainly who your client is and is not.","Explain what the company can do with what they tell you.","Plain language here is a professional obligation, not a style choice."],"focus":["audience","clarity"]},
    {"id":"audience-law-mid-05","level":"mid","profession":"lawyer","title":"Force majeure for the operations manager","scenario":"The client's operations manager asks whether the port strike lets their supplier off the hook under the force majeure clause. Your honest answer: probably yes for delay, no for outright cancellation. Your draft quotes the clause verbatim.","task":"Write a 2-3 sentence answer in operational terms — what the supplier can and cannot do.","tips":["Answer in her terms: late is excused, walking away is not.","Quote nothing; translate everything.","End with the practical move: get the supplier's revised dates in writing."],"focus":["audience","clarity"],"placeholder":"The strike likely excuses late delivery, but not cancellation."},
    {"id":"audience-law-mid-06","level":"mid","profession":"lawyer","title":"Exposure, for the board","scenario":"The GC asked you to draft the litigation paragraph for the board pack. Your memo version says the claim 'presents material contingent liability with meaningful defenses on causation.' Board members are not lawyers and read forty pages before dinner.","task":"Rewrite the paragraph in 2-3 sentences a director can absorb in one pass.","tips":["Numbers and timing first: range of exposure, when it resolves.","Replace 'meaningful defenses' with what you actually think the odds are.","Cut every word a director would have to reread."],"focus":["audience","precision"]},
    {"id":"audience-law-mid-07","level":"mid","profession":"lawyer","title":"Teaching the redline","scenario":"Your junior asked why you always strike the customer's 'sole discretion' acceptance language. You know it so well you're tempted to say 'it's just market.' The junior needs the actual reason to apply it independently next time.","task":"Explain the redline in 3-4 sentences pitched at a smart junior seeing it for the second time.","tips":["Give the failure mode: what goes wrong for the client if the language stays.","One concrete example beats an abstract rule.","End with the test they can apply without you."],"focus":["audience","clarity"]},
    {"id":"audience-law-mid-08","level":"mid","profession":"lawyer","title":"The litigation hold for IT","scenario":"You're sending the litigation hold instructions to the client's IT lead. The template talks about 'suspension of routine document destruction policies pursuant to preservation obligations.' The IT lead needs to know which systems, which auto-delete jobs, and by when.","task":"Write a 3-4 sentence version addressed to the IT lead's actual job.","tips":["Name the systems and the auto-delete jobs, not the doctrine.","Give the deadline and who to confirm to.","Ask the question only IT can answer: what else deletes on a schedule?"],"focus":["audience","precision"],"placeholder":"By Friday, please pause auto-deletion on email, Slack, and the shared drives for these 11 people:"},
    {"id":"audience-law-mid-09","level":"mid","profession":"lawyer","title":"Settlement structure for the CFO","scenario":"The proposed settlement is $900K: $500K now, $400K over two years, with a confidentiality clause and no admission. The CFO cares about cash timing, accounting treatment, and whether this resurfaces. Your draft describes the release mechanics first.","task":"Write a 3-sentence summary of the deal in the CFO's terms.","tips":["Lead with cash: how much, when, from which year's budget.","Flag what she'll ask accounting about — you don't have to answer it.","'No admission and confidential' is one reassuring clause, not a page."],"focus":["audience","precision"]},
    {"id":"audience-law-mid-10","level":"mid","profession":"lawyer","title":"Termination risk for the HR head","scenario":"The client's HR head wants to terminate a sales manager who missed targets — but the manager filed an internal complaint three weeks ago. You see retaliation-claim risk. Your draft memo opens with the elements of a retaliation claim.","task":"Write a 3-4 sentence answer in HR's terms: the risk, what makes it better or worse, the next step.","tips":["Her question is 'can we, and how' — answer that, not the elements.","Timing is the problem; say so plainly.","Give the process that lowers risk: document performance first, revisit in a quarter."],"focus":["audience","clarity"],"placeholder":"Terminating him three weeks after his complaint invites a retaliation claim, even if the targets story is real."},
    {"id":"audience-law-mid-11","level":"mid","profession":"lawyer","title":"Arbitration vs. court for a small-business owner","scenario":"Your client, who owns a regional bakery chain, asks why the franchise agreement pushes disputes to arbitration and whether that's bad for her. She's never litigated anything. Your draft compares discovery rules and appellate rights.","task":"Explain the tradeoff in 3-4 sentences she can use to decide.","tips":["Her stakes: cost, speed, privacy, and whether she can appeal a bad result.","One concrete comparison — 'a dispute like X would cost/take roughly Y in each.'","Skip procedure words entirely: no 'discovery,' no 'appellate.'"],"focus":["audience","clarity"]},
    {"id":"audience-law-mid-12","level":"mid","profession":"lawyer","title":"The letter opposing counsel will show a judge","scenario":"You're writing to opposing counsel about their client's missed discovery obligations. The real audience is double: the lawyer reading it now, and the judge who may see it attached to a motion later. Your current draft is sarcastic in two places.","task":"Rewrite the key paragraph (3-4 sentences) so it lands firm and factual for both readers.","tips":["Write for the judge: dates, obligations, and gaps — no adjectives.","Firm means specific, not sharp.","End with the concrete cure and deadline you're demanding."],"focus":["audience","precision"]},
    {"id":"audience-law-mid-13","level":"mid","profession":"lawyer","title":"'Without prejudice' in plain words","scenario":"Your client wants to email the other side's CEO directly to 'talk settlement, founder to founder.' You need to explain quickly why settlement talk needs protecting and how to do it — without a lecture on evidence rules.","task":"Write a 2-3 sentence explanation and instruction the client will actually follow.","tips":["Lead with the danger: what they say can be quoted back in court if done wrong.","Give the rule of thumb, not the rule: route offers through counsel.","Offer the safe version of what they want — you can open the channel."],"focus":["audience","clarity"],"placeholder":"Anything you write him about settlement can end up in front of the judge unless it's set up right."},
    {"id":"audience-law-mid-14","level":"mid","profession":"lawyer","title":"The regulatory finding, for marketing","scenario":"The consumer-protection review found the client's 'guaranteed results' ad claims are the problem. You must tell the marketing team what to change. Your draft summarizes the regulator's legal theory of deceptive practices.","task":"Write a 3-sentence message telling marketing exactly what to stop, change, and keep.","tips":["Their job is campaigns, not theory: name the phrases that must go.","Say what's still safe to claim — don't leave them guessing.","Deadline and single point of contact for edge cases."],"focus":["audience","clarity"]},
    {"id":"audience-law-mid-15","level":"mid","profession":"lawyer","title":"Limitation of liability for procurement","scenario":"The client's procurement lead asks why you're 'holding up' a vendor contract over the limitation-of-liability clause. The vendor capped everything — including data breaches — at one month of fees, about $8K. A breach could cost the client millions.","task":"Write a 2-3 sentence explanation of the holdup in procurement's terms.","tips":["Translate the cap into their number: $8K against a multimillion-dollar risk.","Frame yourself as protecting their vendor decision, not blocking it.","Name the fix you'd accept so they can push the vendor."],"focus":["audience","impact"],"placeholder":"If this vendor loses your data, this clause limits what you can recover to about $8K."},
    {"id":"audience-law-mid-16","level":"mid","profession":"lawyer","title":"The security interest, for the lender's banker","scenario":"You represent a lender whose deal contact is a banker, not a lawyer. You need to explain that another creditor filed first, so your client's collateral position is second in line for the equipment. Your draft says 'prior perfected security interest takes priority.'","task":"Rewrite in 2-3 sentences the banker can relay to her credit committee.","tips":["Say it as line position: someone is ahead of you on this collateral.","Quantify what that means in a default scenario.","Then the options: different collateral, or a deal with the first creditor."],"focus":["audience","clarity"]},
    {"id":"audience-law-mid-17","level":"mid","profession":"lawyer","title":"What the partner needs vs. what you did","scenario":"You spent the week wrestling a tricky choice-of-law question and are proud of the analysis. Your update to the partner recounts your research journey. The partner needs three things: the answer, the confidence level, and whether it changes strategy.","task":"Write the 3-sentence version calibrated to what the partner will do with it.","tips":["Partners consume conclusions; the journey goes in the research file.","State confidence honestly: 'strong' or 'close call,' with the hinge.","Say explicitly whether strategy changes — that's their next meeting."],"focus":["audience","concision"],"placeholder":"New York law governs — it's a close call, but the contract clause holds."},
    {"id":"audience-law-mid-18","level":"mid","profession":"lawyer","title":"Breach notification for the engineering lead","scenario":"The client had a data incident and you're advising on notification duties. The engineering lead joins the call knowing systems, not statutes. You need her to scope which records were accessed — the legal deadline depends on her answer.","task":"Write the 3-4 sentence briefing that tells her what you need and why it matters, in her terms.","tips":["Her deliverable first: which records, which fields, how many people.","Tie her answer to the consequence: it sets a legal clock.","Give the timeframe you need it in and what 'good enough for now' looks like."],"focus":["audience","precision"]},
    {"id":"audience-law-mid-19","level":"mid","profession":"lawyer","title":"The engagement scope for a first-timer","scenario":"A new client — a family-owned manufacturer facing its first lawsuit — just received your standard engagement letter and called confused about 'phases,' 'disbursements,' and what they're actually buying. You're writing the cover note that should have prevented the call.","task":"Write a 3-4 sentence cover note explaining what happens next and what it costs, for someone who has never hired litigators.","tips":["Walk their next 90 days, not the litigation lifecycle.","Money in plain terms: what's estimated, what's billed as it goes.","Name the one decision they'll face soonest."],"focus":["audience","clarity"]},
    {"id":"audience-law-mid-20","level":"mid","profession":"lawyer","title":"The escrow holdback for selling founders","scenario":"You represent two founders selling their company. The buyer wants 15% of the price held in escrow for 18 months against indemnity claims. The founders see it as the buyer 'keeping their money.' Your draft explains indemnification mechanics.","task":"Explain the holdback in 3 sentences from the founders' seat: what they get, when, and what could shrink it.","tips":["Their frame: $3M of your $20M arrives in 18 months if nothing surfaces.","Name what realistically triggers claims — not the parade of horribles.","Then your job: the negotiation levers that protect the 15%."],"focus":["audience","clarity"],"placeholder":"Think of it as $3M of your price arriving in 18 months, minus any problems the buyer finds that you promised didn't exist."},
    {"id":"audience-law-mid-21","level":"mid","profession":"lawyer","title":"The all-hands line about the lawsuit","scenario":"The client's CEO wants a sentence to say at the company all-hands about the well-publicized lawsuit — honest, calm, and safe if it's quoted in a filing later. Your draft is either a no-comment or a paragraph of qualifiers.","task":"Write 1-2 sentences the CEO can say aloud that inform employees without creating evidence problems.","tips":["Audience is employees; the shadow audience is the courtroom.","Facts and posture only: we're defending it, work continues, don't discuss externally.","No predictions, no characterizations of the other side."],"focus":["audience","precision"]},
    {"id":"audience-law-mid-22","level":"mid","profession":"lawyer","title":"The non-compete answer for the hiring manager","scenario":"A client's engineering manager wants to hire a rival's senior developer who has a one-year non-compete. The manager asks 'is it enforceable?' The useful answer is about what the hire can and can't do on day one, and what paper to avoid creating.","task":"Write a 3-4 sentence answer organized around the manager's hiring decision.","tips":["Reframe from 'enforceable?' to 'what can she safely do here?'","Concrete day-one guidance: role scope, no rival customer contact, no files.","Flag the letter the rival will send, so it doesn't cause panic."],"focus":["audience","clarity"]},
    {"id":"audience-law-mid-23","level":"mid","profession":"lawyer","title":"Why the deal can't sign Friday","scenario":"The client's sales VP promised the customer a Friday signature. The customer's latest draft added an IP-ownership clause that would hand over the client's core code. The VP hears legal delay; you need him to hear product risk.","task":"Write a 2-3 sentence message that puts the problem in the VP's terms and gives him a path to Friday.","tips":["Translate the clause into his stake: it gives away the product he's selling.","Offer the path: your replacement language is ready — customer accepts, you sign Friday.","Make the customer's lawyer the bottleneck, not you."],"focus":["audience","impact"],"placeholder":"The customer's new clause would hand them ownership of our core code — sign it and we can't sell the product to anyone else."},
    {"id":"audience-law-mid-24","level":"mid","profession":"lawyer","title":"Altitude check for the deputy GC","scenario":"The client's deputy GC — a former litigator — asked for your take on the venue motion. Your draft explains what a venue motion is, as you would for a business reader. For her, that reads as either padding or condescension.","task":"Rewrite your 3-sentence answer at the altitude of a lawyer who knows procedure but not this case.","tips":["Skip what any litigator knows; spend words on what only you know — this judge, this record.","Lead with your call and the odds.","Peer altitude: state disagreement-ready conclusions, not tutorials."],"focus":["audience","concision"]},
    {"id":"audience-law-mid-25","level":"mid","profession":"lawyer","title":"The coverage position for the broker","scenario":"The client's insurance broker asks where the claim stands with the carrier. The carrier accepted defense under a reservation of rights, and the fight ahead is about whether the 'intentional acts' exclusion applies. The broker knows insurance, not this dispute.","task":"Write a 3-sentence status in broker's terms — covered, contested, and what would change it.","tips":["Use her frame: defense is being paid; indemnity is the open question.","Name the exclusion in play and the fact fight underneath it.","Tell her what you need from the placement file, if anything."],"focus":["audience","precision"]}
  ],
  "structure-that-carries": [
    {"id":"structure-law-mid-01","level":"mid","profession":"lawyer","title":"Three reasons to settle, grouped","scenario":"You're recommending settlement to the client and have eleven supporting points scattered across your notes — trial risk, cost, distraction, a bad witness, an unfavorable judge, and more. Your draft lists all eleven in the order you thought of them.","task":"Group the case for settling under three governing buckets and write the topic sentence for each.","tips":["Collapse eleven points into at most three themes — risk, cost, distraction.","Each bucket gets one clear label a client can hold.","Order the buckets by what moves this client most."],"focus":["structure","clarity"],"placeholder":"We recommend settling for three reasons: the odds, the cost, and the distraction."},
    {"id":"structure-law-mid-02","level":"mid","profession":"lawyer","title":"SCQA for the advice memo","scenario":"You're opening a memo advising whether the client can enforce the exclusivity clause against a distributor who's quietly selling to a competitor. You tend to start memos with a recitation of the facts and let the question emerge later.","task":"Write a 4-sentence opening using situation, complication, question, answer.","tips":["Situation: the exclusive deal as both sides understood it.","Complication: the distributor's side sales.","Question then answer — don't make the reader hunt for either."],"focus":["structure","clarity"]},
    {"id":"structure-law-mid-03","level":"mid","profession":"lawyer","title":"PREP for the partner's spoken question","scenario":"The partner asks in the hallway: \"Should we take the deposition of their CFO or not?\" You have a clear view — yes — but you tend to think out loud and circle the answer.","task":"Answer aloud in the PREP shape: point, reason, example, point.","tips":["Point: yes, depose him.","One reason, one concrete example from the record.","Land back on the point so the partner can act."],"focus":["structure","concision"],"placeholder":"Yes, take it. He's the one witness who can authenticate the emails, and"},
    {"id":"structure-law-mid-04","level":"mid","profession":"lawyer","title":"The messy issues list","scenario":"Your due-diligence review turned up fourteen contract issues in the target company, ranging from a missing signature to a change-of-control clause that could blow up the deal. Your draft to the deal team is a flat list of fourteen.","task":"Reorganize the fourteen into a structure that separates deal-breakers from cleanup, and write the two headers plus the top item under each.","tips":["Group by consequence, not by contract.","Deal-breakers first, each with the 'so what.'","Cleanup items can be a single line — signal they're minor."],"focus":["structure","precision"]},
    {"id":"structure-law-mid-05","level":"mid","profession":"lawyer","title":"One governing idea for the strategy memo","scenario":"Your litigation strategy memo covers discovery plans, motion practice, settlement posture, and budget. Right now it reads as four disconnected sections with no thesis tying them together.","task":"Write the single governing sentence the whole memo supports, then name the 3 sections beneath it.","tips":["One thesis: what is the strategy, in a sentence?","Every section should ladder up to that sentence.","Three buckets max — merge or cut a fourth."],"focus":["structure","clarity"],"placeholder":"Our strategy is to make trial expensive enough that they settle by fall — which drives three choices:"},
    {"id":"structure-law-mid-06","level":"mid","profession":"lawyer","title":"Structuring the counteroffer email","scenario":"You're relaying your client's counteroffer to opposing counsel: the number, three deal terms attached to it, and a deadline. Your draft mixes the number, terms, and deadline into one dense paragraph.","task":"Restructure into a clear opening line plus a short labeled list of the terms.","tips":["Number and deadline in the opening sentence.","The three conditions as a scannable list, not prose.","Structure signals seriousness to the other side."],"focus":["structure","clarity"]},
    {"id":"structure-law-mid-07","level":"mid","profession":"lawyer","title":"The junior's shapeless brief","scenario":"A junior's argument section makes four points but they blur together — no headings, no hierarchy, and the strongest point is third. You're about to give structural feedback.","task":"Write 3 sentences of feedback that give the junior a reusable structure, not just a reorder.","tips":["Name the principle: lead with the strongest argument.","One point per heading, in descending strength.","Give the test they can apply to the next brief alone."],"focus":["structure","clarity"]},
    {"id":"structure-law-mid-08","level":"mid","profession":"lawyer","title":"The compliance answer with three conditions","scenario":"The business team asks whether they can run the customer-referral promotion. The answer is yes, but only if three conditions hold: clear disclosure, no cash to consumers, and records kept. Your draft explains the regulatory basis before the conditions.","task":"Structure a reply that gives the answer, then the three conditions as a clean list.","tips":["Yes-if, up front: it works under these three conditions.","Number the conditions so the team can check them off.","Regulatory basis is a footnote they can request."],"focus":["structure","clarity"],"placeholder":"Yes, you can run it — as long as three things hold:"},
    {"id":"structure-law-mid-09","level":"mid","profession":"lawyer","title":"Framing the client's decision","scenario":"The client must decide whether to appeal. You're structuring an email around one governing question with the sub-issues beneath it: odds of reversal, cost, and time. Your draft wanders between them.","task":"Write the governing question and the 3 sub-questions the client must weigh, each in one line.","tips":["One decision at the top, phrased as a question.","Three inputs beneath it — odds, cost, time.","Keep parallel structure so the choice is legible."],"focus":["structure","clarity"]},
    {"id":"structure-law-mid-10","level":"mid","profession":"lawyer","title":"The status update that needs a spine","scenario":"Your monthly report to the client covers three active matters. Right now it's chronological — everything that happened in each, in date order — and the client can't tell what needs attention.","task":"Restructure around one line per matter: status, next milestone, and any decision needed.","tips":["One matter, three data points — status, next date, ask.","Lead each with a green/amber/red judgment, not a narrative.","Put the matter needing a decision first."],"focus":["structure","concision"]},
    {"id":"structure-law-mid-11","level":"mid","profession":"lawyer","title":"SCQA for the risk escalation","scenario":"You need to escalate to the partner that a key witness has become uncooperative and may need to be subpoenaed, which changes the trial timeline. Your draft opens mid-problem without setting it up.","task":"Write a 4-sentence escalation using situation, complication, question, answer.","tips":["Situation: the witness we were relying on voluntarily.","Complication: she's gone quiet and lawyered up.","Question — subpoena or not — then your recommended answer."],"focus":["structure","impact"]},
    {"id":"structure-law-mid-12","level":"mid","profession":"lawyer","title":"Grouping the client's questions","scenario":"The client sent nine questions about the merger agreement in a single stream-of-consciousness email — some legal, some commercial, some just needing a pointer. Your draft answers them one by one in the order asked.","task":"Regroup your reply into 2-3 labeled clusters and write the cluster headers plus the lead answer in each.","tips":["Group by type: what's a real legal issue, what's commercial, what's a quick pointer.","Answer the cluster that carries risk first.","Headers let the client route each question to the right person."],"focus":["structure","audience"]},
    {"id":"structure-law-mid-13","level":"mid","profession":"lawyer","title":"PREP for the settlement recommendation","scenario":"In a call with the client's leadership, someone asks: \"Why not just fight this?\" You believe settlement is right but tend to list every risk factor rather than build an argument.","task":"Answer aloud in PREP form: point, one reason, one example, point.","tips":["Point: because fighting costs more than we'd likely win.","Reason plus a single vivid example from the case.","Return to the recommendation so they can decide."],"focus":["structure","concision"],"placeholder":"Because the math doesn't favor it. Even a win nets less than the settlement after fees, and"},
    {"id":"structure-law-mid-14","level":"mid","profession":"lawyer","title":"The demand letter's architecture","scenario":"You're drafting a demand letter with facts, the legal basis, the demand, and a deadline. Your first draft blends facts and argument throughout, so the recipient can't find the actual demand.","task":"Lay out the letter's four sections in order and write the one-line purpose of each.","tips":["Facts, then basis, then demand, then deadline — clean sections.","The demand and deadline must be findable in five seconds.","Keep argument out of the facts section."],"focus":["structure","precision"]},
    {"id":"structure-law-mid-15","level":"mid","profession":"lawyer","title":"One idea for the closing argument outline","scenario":"You're helping the partner outline the closing. Right now it's a pile of favorable facts with no organizing theory of the case. The jury needs one story, not a fact dump.","task":"Write the single theory sentence and the 3 evidentiary pillars that support it.","tips":["One sentence a juror could repeat in the hallway.","Three pillars, each a group of facts, not a fact.","Everything that doesn't support the theory gets cut or subordinated."],"focus":["structure","clarity"]},
    {"id":"structure-law-mid-16","level":"mid","profession":"lawyer","title":"The contract-review summary","scenario":"You reviewed a 40-page services agreement for the business team and flagged twelve items. Your draft is a page-ordered walkthrough, so the team can't tell which flags block signing.","task":"Restructure into three buckets — must fix, should fix, note only — and write the header and top item for each.","tips":["Sort by action needed, not by page number.","'Must fix' first, each with the risk if left.","'Note only' can be a single collapsed line."],"focus":["structure","impact"],"placeholder":"Three buckets. Must fix before signing:"},
    {"id":"structure-law-mid-17","level":"mid","profession":"lawyer","title":"The board briefing on litigation","scenario":"The GC asked you to structure a five-minute litigation update for the board covering four cases. Your notes are dense and case-by-case with no through-line.","task":"Write the one framing sentence for the whole portfolio, then the single line you'd say per case.","tips":["Frame the portfolio first: total exposure, trend, biggest mover.","One line per case — status and the number, nothing else.","End with the one case that needs a board decision."],"focus":["structure","concision"]},
    {"id":"structure-law-mid-18","level":"mid","profession":"lawyer","title":"Ordering the deposition outline","scenario":"Your deposition outline for the opposing engineer has topics scattered as they occurred to you — background mixed with the key admissions you're chasing. You want a structure that builds.","task":"Name the 3-part arc for the outline and the goal of each part in one line.","tips":["Lock in facts before the witness knows where you're going.","Save the key admission for after the fences are built.","Each section has one objective, stated plainly."],"focus":["structure","precision"]},
    {"id":"structure-law-mid-19","level":"mid","profession":"lawyer","title":"The two-path recommendation","scenario":"You're advising the client on a contract dispute where there are genuinely two viable paths — renegotiate or terminate. Your draft describes each path's steps but never structures the choice itself.","task":"Structure the email as one decision with two clearly parallel options and your recommended path.","tips":["State the decision, then Option A / Option B in parallel form.","Same three factors compared across both — cost, speed, relationship.","Name your pick; parallel structure makes the tradeoff obvious."],"focus":["structure","clarity"]},
    {"id":"structure-law-mid-20","level":"mid","profession":"lawyer","title":"Bucketing the compliance gaps","scenario":"A compliance review of the client's vendor contracts found gaps across data protection, insurance, and termination rights. Your draft lists 18 gaps flat. Leadership needs to see the shape of the problem.","task":"Group the gaps under 3 themes and write each theme's header and headline finding.","tips":["Three themes, each a category of risk.","Lead each theme with its worst instance.","A count per theme shows scale without listing all 18."],"focus":["structure","precision"]},
    {"id":"structure-law-mid-21","level":"mid","profession":"lawyer","title":"The SCQA cover note for the report","scenario":"You're sending the client a 30-page investigation report and need a cover note that frames why it matters. Your draft just says 'please find attached the report' and lists the sections.","task":"Write a 4-sentence cover note in SCQA form so the client reads the report with the right lens.","tips":["Situation and complication set up why the investigation happened.","The question is what the client actually wanted to know.","Answer it in the note; the report is the support."],"focus":["structure","audience"]},
    {"id":"structure-law-mid-22","level":"mid","profession":"lawyer","title":"Feedback on a structureless client letter","scenario":"Your junior drafted a client advice letter that answers the question but wanders — the recommendation appears in paragraph five and the reasoning loops. You're giving structural feedback she can reuse.","task":"Write 3 sentences of feedback naming the structure the letter should follow.","tips":["Answer first, then reasons, then caveats — say it as a template.","Point to the exact paragraph that should have led.","Make it a rule she applies next time without you."],"focus":["structure","clarity"]},
    {"id":"structure-law-mid-23","level":"mid","profession":"lawyer","title":"The negotiation prep grid","scenario":"You're prepping for a contract negotiation with five open terms and need to walk the client through your strategy. Your draft discusses the terms in random order with no priority framing.","task":"Structure the prep around must-haves, tradeables, and give-aways, with one term named in each.","tips":["Three tiers by how hard you'll fight for each.","Put the must-have first and say why it's non-negotiable.","This grid becomes the client's decision map at the table."],"focus":["structure","precision"],"placeholder":"Three tiers going in. Must-haves — the liability cap:"},
    {"id":"structure-law-mid-24","level":"mid","profession":"lawyer","title":"One idea for the appeal recommendation","scenario":"You're recommending against appeal. Your draft lists six weaknesses in the appellate position with equal weight, and the client can't see the core reason.","task":"Write the one governing sentence for your recommendation, then the 2-3 supporting pillars.","tips":["One reason at the top that would stand alone.","Two or three pillars beneath, in order of weight.","Six equal points read as no point — subordinate the minor ones."],"focus":["structure","impact"]},
    {"id":"structure-law-mid-25","level":"mid","profession":"lawyer","title":"The PREP answer to a skeptical CFO","scenario":"On a call, the client's CFO challenges you: \"Do we really need outside counsel for this, or can we handle it in-house?\" You think outside help is warranted for one specific reason but tend to over-explain.","task":"Answer aloud in PREP form in under 30 seconds.","tips":["Point: yes, for this piece specifically.","One reason, one example of what goes wrong without it.","Land back on the narrow scope so it doesn't sound like empire-building."],"focus":["structure","concision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-law-mid-01","level":"mid","profession":"lawyer","title":"The hedged advice email","scenario":"Your draft to the client reads: \"It would appear that, in all likelihood, there may potentially be some risk that the clause could arguably be found unenforceable.\" You know the answer: it's probably unenforceable.","task":"Rewrite the sentence in plain, direct language without stacking hedges.","tips":["One hedge, if any — not five.","'Probably unenforceable' says it; the rest is padding.","Clients read confidence in concision."],"focus":["concision","clarity"],"placeholder":"The clause is probably unenforceable."},
    {"id":"concise-law-mid-02","level":"mid","profession":"lawyer","title":"Nominalizations in the memo","scenario":"Your memo says \"the making of a determination as to the applicability of the exclusion requires the undertaking of an analysis.\" It's four verbs hiding inside nouns. The partner wants tighter prose.","task":"Rewrite in one direct sentence using real verbs.","tips":["Turn 'making a determination' into 'decide,' 'undertaking an analysis' into 'analyze.'","Cut 'as to the applicability of' to 'whether.'","Verbs move; nouns sit."],"focus":["concision","clarity"],"placeholder":"To decide whether the exclusion applies, we analyze"},
    {"id":"concise-law-mid-03","level":"mid","profession":"lawyer","title":"The email that halved","scenario":"Your update to the partner is two dense paragraphs, but the actual content is: discovery is on track, one deposition slipped a week, no budget impact. The rest is throat-clearing and context she already has.","task":"Cut it to 3 sentences that carry the same information.","tips":["Keep the three facts; drop the context she owns.","No 'I wanted to reach out to let you know that.'","If a sentence survives only as courtesy, cut it."],"focus":["concision","clarity"]},
    {"id":"concise-law-mid-04","level":"mid","profession":"lawyer","title":"Redundant legal pairs","scenario":"Your client-facing letter is full of doublets: 'null and void,' 'terms and conditions,' 'due and payable,' 'each and every,' 'cease and desist.' For a business reader, they add length without meaning.","task":"Rewrite a 3-sentence passage stripping the redundant pairs to single words.","tips":["Pick the one word that carries the meaning: 'void,' 'payable,' 'every.'","Doublets are habit, not precision, in a business letter.","Keep the pair only where it's a genuine term of art."],"focus":["concision","precision"]},
    {"id":"concise-law-mid-05","level":"mid","profession":"lawyer","title":"Meta-commentary in the client note","scenario":"Your note opens: \"I wanted to take a moment to circle back and provide you with an update regarding where things currently stand with respect to the matter we discussed.\" The actual update hasn't started yet.","task":"Delete the meta-commentary and write the sentence that should open the note.","tips":["Everything before the first fact is deletable.","Start with what happened, not with the fact that you're about to say it.","'Here's where the case stands' is already too much — just say where it stands."],"focus":["concision","clarity"],"placeholder":"The court set trial for October 14."},
    {"id":"concise-law-mid-06","level":"mid","profession":"lawyer","title":"The bloated cover email","scenario":"You're sending the client a redlined contract. Your cover email spends five sentences apologizing for the turnaround and explaining your process before getting to the two changes that matter.","task":"Rewrite the email to 2-3 sentences that lead with the two substantive changes.","tips":["Cut the apology and the process narrative.","Name the two changes and why they matter.","A busy client wants the diff, not the diary."],"focus":["concision","impact"]},
    {"id":"concise-law-mid-07","level":"mid","profession":"lawyer","title":"Tightening the junior's prose","scenario":"A junior's brief passage runs 90 words to say the contract was signed, then breached, then the client suffered losses. You're modeling the edit rather than just fixing it.","task":"Cut the passage to under 30 words and note the one principle you applied.","tips":["Three facts, three short sentences — signed, breached, harmed.","Strike every 'the fact that' and 'in order to.'","Name the principle: say it once, in the fewest words that stay accurate."],"focus":["concision","clarity"]},
    {"id":"concise-law-mid-08","level":"mid","profession":"lawyer","title":"The filler-heavy voicemail","scenario":"Your voicemail draft to opposing counsel is: \"Hi, it's me, I was just calling to sort of touch base and see if maybe we could possibly find some time to discuss the scheduling issue at some point.\" It says almost nothing.","task":"Rewrite the voicemail to two crisp sentences with a concrete ask.","tips":["Cut 'sort of,' 'maybe,' 'possibly,' 'at some point.'","Name the issue and propose a specific time.","Vagueness reads as weakness to the other side."],"focus":["concision","clarity"],"placeholder":"It's [name] on the Hartwell matter. Can we talk Thursday about moving the deposition dates?"},
    {"id":"concise-law-mid-09","level":"mid","profession":"lawyer","title":"The over-qualified recommendation","scenario":"Your settlement recommendation is buried under qualifiers: \"subject to further review, and without prejudice to our final assessment, and recognizing the inherent uncertainties, we tentatively lean toward possibly recommending settlement.\" The client can't find the recommendation.","task":"State the recommendation in one clean sentence, keeping only the caveat that genuinely matters.","tips":["Recommend, don't 'tentatively lean toward possibly.'","Keep the one real caveat; delete the reflexive ones.","A recommendation drowned in qualifiers isn't a recommendation."],"focus":["concision","impact"],"placeholder":"We recommend settling, assuming the final financials confirm the numbers you gave us."},
    {"id":"concise-law-mid-10","level":"mid","profession":"lawyer","title":"Halving the risk paragraph","scenario":"Your memo's risk section is a 150-word paragraph that repeats the same point — regulatory exposure — three ways. The client's GC flagged that memos run long.","task":"Cut the paragraph to under 75 words without losing a substantive point.","tips":["Find the point stated three times; keep the sharpest version.","Delete transition sentences that only restate.","Half the words, all the risk."],"focus":["concision","clarity"]},
    {"id":"concise-law-mid-11","level":"mid","profession":"lawyer","title":"The wordy contract clause","scenario":"You're drafting a notice provision that currently reads: \"In the event that either party shall desire to provide notice to the other party, such notice shall be required to be provided in written form.\" It's a simple rule swollen with legalese.","task":"Rewrite the clause in one tight, still-precise sentence.","tips":["'In the event that' is 'if.' 'Shall desire to' is 'wants to' or just cut.","Precision doesn't require padding.","Read it aloud — if you run out of breath, it's too long."],"focus":["concision","precision"],"placeholder":"Any notice under this agreement must be in writing."},
    {"id":"concise-law-mid-12","level":"mid","profession":"lawyer","title":"The status call with no headline","scenario":"You're about to give a spoken status on a call and your notes ramble across everything that happened. The client has three minutes and one real question: are we still on track for trial?","task":"Deliver the status aloud in under 30 seconds, leading with the answer to their real question.","tips":["Answer 'on track?' in the first breath.","Two supporting facts, then stop.","Silence after a tight answer invites the right follow-up."],"focus":["concision","clarity"]},
    {"id":"concise-law-mid-13","level":"mid","profession":"lawyer","title":"Cutting the throat-clearing intro","scenario":"Your advice memo spends its first paragraph explaining that you were asked to advise, what you reviewed, and the limitations of your review — before saying anything useful. The client already knows why they hired you.","task":"Cut the intro to a single line and write the sentence that should actually open the memo.","tips":["Scope caveats belong at the end, in one line, not the opening.","Start with the answer or the key finding.","The reader's attention is highest at word one — don't waste it."],"focus":["concision","structure"]},
    {"id":"concise-law-mid-14","level":"mid","profession":"lawyer","title":"The over-explained 'no'","scenario":"The business team asked if they can use a competitor's trademark in a comparison ad. The answer is no. Your draft reply runs three paragraphs of trademark theory before the reader learns they can't.","task":"Rewrite as 2-3 sentences: the no, the one-line reason, the safe alternative.","tips":["Lead with the no; theory doesn't change it.","One sentence of why, in their terms.","Give the alternative they can actually use."],"focus":["concision","clarity"],"placeholder":"No — don't use their trademark in the ad. Here's what you can do instead:"},
    {"id":"concise-law-mid-15","level":"mid","profession":"lawyer","title":"The bloated deadline reminder","scenario":"You're reminding the client's team about a discovery deadline. Your draft rehashes the entire litigation history before stating what's due and when. The team just needs the ask.","task":"Cut to two sentences: what's needed, by when, from whom.","tips":["Delete the history; they lived it.","The date and the deliverable are the whole message.","One owner, one deadline, done."],"focus":["concision","impact"]},
    {"id":"concise-law-mid-16","level":"mid","profession":"lawyer","title":"Redundant 'in order to' and friends","scenario":"Your motion draft is peppered with 'in order to,' 'for the purpose of,' 'in the event that,' 'with respect to,' and 'prior to.' The partner asked you to tighten it before filing.","task":"Rewrite a 3-sentence passage replacing each phrase with its one-word equivalent.","tips":["'In order to' is 'to.' 'Prior to' is 'before.' 'With respect to' is 'about.'","These phrases add length, never meaning.","Judges read faster prose more favorably."],"focus":["concision","clarity"]},
    {"id":"concise-law-mid-17","level":"mid","profession":"lawyer","title":"The email that says it twice","scenario":"Your email to the client makes its main point in the opening, then restates it in nearly identical words in the closing 'to summarize.' The middle adds nothing new. It's padded to feel thorough.","task":"Cut the email to a single tight statement of the point plus its one supporting fact.","tips":["Say it once, well.","'To summarize' is a tell that you already said it.","Length is not thoroughness."],"focus":["concision","clarity"]},
    {"id":"concise-law-mid-18","level":"mid","profession":"lawyer","title":"The passive-voice pileup","scenario":"Your letter reads: \"It was determined by the review team that the obligations had not been met by the vendor, and it is recommended that action be taken.\" Everyone is hidden behind the passive.","task":"Rewrite in active voice, naming who did what, in one or two sentences.","tips":["Name the actor: the review found, the vendor missed, we recommend.","Active voice is shorter and clearer at once.","Passive hides accountability — make it visible."],"focus":["concision","precision"],"placeholder":"Our review found the vendor missed its obligations; we recommend acting now."},
    {"id":"concise-law-mid-19","level":"mid","profession":"lawyer","title":"Trimming the negotiation recap","scenario":"After a two-hour negotiation, your recap email to the client narrates every exchange. The client needs to know only where things landed and what's still open.","task":"Cut the recap to 3 sentences: what's agreed, what's open, next step.","tips":["Blow-by-blow belongs in your file, not their inbox.","Two states — agreed and open — plus the next move.","The client will forward the short version; write that one."],"focus":["concision","structure"]},
    {"id":"concise-law-mid-20","level":"mid","profession":"lawyer","title":"The over-caveated engagement scope","scenario":"Your scope note to a new client hedges every deliverable: \"we may, depending on circumstances, potentially prepare, subject to your instructions, certain documents as appropriate.\" The client can't tell what they're getting.","task":"Rewrite one deliverable line as a clear commitment.","tips":["Say what you'll do, plainly.","Conditions get one clause, not a fog.","Clients pay for clarity about what they're buying."],"focus":["concision","clarity"],"placeholder":"We'll draft and negotiate the supply agreement through signing."},
    {"id":"concise-law-mid-21","level":"mid","profession":"lawyer","title":"The filler-padded opinion","scenario":"Your opinion sentence is: \"It is our considered view that, on balance and taking everything into account, the position is, generally speaking, a reasonably strong one.\" The strength assessment is drowned in cushioning.","task":"Rewrite as one direct sentence stating the strength.","tips":["Cut 'it is our considered view that' — the memo is your view.","'On balance,' 'generally speaking,' 'reasonably' can't all stay.","Say strong, moderate, or weak, and mean it."],"focus":["concision","impact"],"placeholder":"Our position is strong."},
    {"id":"concise-law-mid-22","level":"mid","profession":"lawyer","title":"The list that should be a sentence","scenario":"Your email uses a five-bullet list to convey what is really one simple point: the contract auto-renews unless cancelled 60 days out. The bullets fragment a single idea.","task":"Collapse the bullets into one clean sentence.","tips":["Not everything wants a list; one idea wants one sentence.","State the rule and the deadline together.","Bullets are for parallel items, not for one thought."],"focus":["concision","structure"],"placeholder":"The contract renews automatically unless you cancel 60 days before the term ends."},
    {"id":"concise-law-mid-23","level":"mid","profession":"lawyer","title":"Cutting the reflexive apology","scenario":"Your email to the partner opens with two sentences of apology for the delay before the substance. The delay was one day and she didn't flag it. The apology weakens the message that follows.","task":"Cut the apology and write the direct opening line.","tips":["A day's delay she didn't notice needs no apology.","Open with the substance; it reads as confidence.","If an apology is truly owed, one clause at the end suffices."],"focus":["concision","impact"]},
    {"id":"concise-law-mid-24","level":"mid","profession":"lawyer","title":"The dense diligence finding","scenario":"Your diligence summary line runs: \"Analysis of the corporate records revealed the existence of a potential issue relating to the possible absence of proper authorization for the 2019 share issuance.\" It buries a simple finding.","task":"Rewrite as one direct finding.","tips":["'Revealed the existence of a potential issue relating to' is 'the records suggest.'","Name the finding: the 2019 issuance may lack proper authorization.","Diligence readers scan dozens of these — make yours land fast."],"focus":["concision","precision"],"placeholder":"The 2019 share issuance may not have been properly authorized."},
    {"id":"concise-law-mid-25","level":"mid","profession":"lawyer","title":"The spoken answer that overstays","scenario":"On a client call, asked a yes/no question about whether a clause survives termination, you tend to give the answer then keep talking, adding qualifications until the client isn't sure what you concluded.","task":"Script a spoken answer under 20 seconds: the yes/no, one reason, then stop.","tips":["Answer, one reason, silence.","Talking past the answer erodes it.","Trust the client to ask a follow-up if they need one."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-law-mid-01","level":"mid","profession":"lawyer","title":"'Strong case' with no numbers","scenario":"Your email tells the client you have \"a strong case with a good chance of success.\" The GC pushes back: what does 'good chance' mean when she has to reserve for it? You do have a view — roughly 65-70% on liability.","task":"Rewrite the assessment with a concrete probability and what it's based on.","tips":["Replace 'good chance' with a range you'd defend: 65-70%.","Say what the estimate rests on — the documents, the venue.","A number lets the GC do her job; an adjective doesn't."],"focus":["precision","clarity"],"placeholder":"On liability, we put the odds at 65-70%, based on the contemporaneous emails and this court's history."},
    {"id":"precision-law-mid-02","level":"mid","profession":"lawyer","title":"'Soon' and 'shortly' in the timeline","scenario":"Your update says the ruling should come \"soon,\" discovery will close \"shortly,\" and trial is \"a ways off.\" The client is trying to plan around these and can't. You know the actual dates or ranges.","task":"Rewrite the three vague timeframes as dates or bounded ranges.","tips":["'Soon' becomes 'within 30-60 days,' or the actual date.","If you truly don't know, say the outer bound you'd bet on.","Dates let a client plan; adjectives make them ask again."],"focus":["precision","clarity"]},
    {"id":"precision-law-mid-03","level":"mid","profession":"lawyer","title":"The exposure range the client can use","scenario":"The client asks what the lawsuit could cost. You've said \"it could be significant.\" You actually estimate $1.5-3M in damages plus $400-600K in fees through trial. That's what they need to reserve.","task":"State the exposure as bounded ranges for damages and fees, with the key driver of the spread.","tips":["Two numbers, not 'significant.'","Name what widens the range — the damages theory that's still live.","Precision here is the difference between a reserve and a guess."],"focus":["precision","impact"],"placeholder":"Plan for $1.5-3M in damages and $400-600K in fees through trial; the spread turns on whether their lost-profits theory survives."},
    {"id":"precision-law-mid-04","level":"mid","profession":"lawyer","title":"So-what for the diligence finding","scenario":"Your diligence memo notes: \"The target has three pending employment claims.\" True, but the deal team doesn't know if that's a rounding error or a dealbreaker. You've assessed the combined exposure at under $150K.","task":"Rewrite the finding with the number and the so-what for the deal.","tips":["The finding is data; add the insight — is this material to a $40M deal?","Quantify: combined exposure under $150K, all likely nuisance-value.","Tell them what to do: no price adjustment, standard indemnity covers it."],"focus":["precision","impact"]},
    {"id":"precision-law-mid-05","level":"mid","profession":"lawyer","title":"Pass the skeptic test","scenario":"You wrote that the non-compete is \"likely unenforceable.\" A skeptical partner asks: says who, and why? Your basis is a specific state statute and two recent appellate decisions narrowing such clauses.","task":"Rewrite the claim so it survives the skeptic — cite the specific authority.","tips":["'Likely unenforceable' plus the statute and cases that make it so.","Name the rule, not just the conclusion.","A claim a skeptic can't dent is worth more than a confident adjective."],"focus":["precision","clarity"]},
    {"id":"precision-law-mid-06","level":"mid","profession":"lawyer","title":"'Many' and 'often' in the review","scenario":"Your contract-review summary says the vendor agreements have \"many\" problematic clauses and the client \"often\" agrees to bad terms. Leadership can't gauge scale. You reviewed 40 contracts; 12 had the problem.","task":"Rewrite with the actual counts and rate.","tips":["'Many' becomes '12 of 40.'","'Often' becomes a rate they can act on.","Counts turn a vague worry into a fixable problem."],"focus":["precision","impact"],"placeholder":"12 of the 40 vendor contracts we reviewed cap liability below the risk — 30%."},
    {"id":"precision-law-mid-07","level":"mid","profession":"lawyer","title":"The settlement math, shown","scenario":"You're recommending settlement at $700K but your email just asserts it's \"the economically rational choice.\" The CFO wants the math: expected trial value net of fees versus the certain $700K.","task":"Lay out the comparison in numbers: expected trial outcome minus fees versus the settlement.","tips":["Expected value: probability times likely award, minus fees.","Put it against the certain $700K.","Show the arithmetic so the recommendation defends itself."],"focus":["precision","impact"]},
    {"id":"precision-law-mid-08","level":"mid","profession":"lawyer","title":"'Recently' and 'a while ago' in the facts","scenario":"Your fact summary says the breach happened \"recently,\" the client complained \"a while ago,\" and the contract was signed \"some years back.\" For a limitations analysis, the exact dates decide the case.","task":"Rewrite the three events with specific dates and note why they matter here.","tips":["Every date matters for limitations — pin each one.","'A while ago' could be inside or outside the window; find out.","Precision on dates isn't pedantry; it's the analysis."],"focus":["precision","clarity"]},
    {"id":"precision-law-mid-09","level":"mid","profession":"lawyer","title":"The data table into one insight","scenario":"You pulled the client's 24 months of chargeback data for the merchant dispute — a dense table. The client doesn't need the table; they need the one pattern that supports the claim: chargebacks tripled after the processor's system change.","task":"Write the one-sentence insight the data supports, with the number.","tips":["Don't paste the table; state what it proves.","One number that carries the argument: 3x after the change.","Tie the pattern to the date of the processor's change."],"focus":["precision","impact"],"placeholder":"Chargebacks tripled in the three months after the processor changed its system, from 40 to 120 a month."},
    {"id":"precision-law-mid-10","level":"mid","profession":"lawyer","title":"'Better' contract terms, unquantified","scenario":"You tell the business team your redline gets them \"much better\" terms. They ask how much better. The liability cap moved from $50K to $2M and the payment window from 90 to 30 days.","task":"Rewrite with the before/after numbers on the two terms that matter.","tips":["'Better' means nothing; $50K to $2M means something.","Two concrete swings, before and after.","Numbers let the business decide if it's worth the friction."],"focus":["precision","impact"]},
    {"id":"precision-law-mid-11","level":"mid","profession":"lawyer","title":"The confidence the client can bank","scenario":"Asked whether the regulator will approve the transaction, you said \"probably fine.\" The client is committing $10M on your read. You'd actually put it at 80%+ with one specific open question about the market-share test.","task":"Rewrite as a calibrated probability plus the one open variable.","tips":["Give the number: 80%+, not 'probably fine.'","Name the single thing that could move it.","Calibration lets the client size the bet."],"focus":["precision","clarity"]},
    {"id":"precision-law-mid-12","level":"mid","profession":"lawyer","title":"So-what for the deposition admission","scenario":"You report to the partner that \"the witness made some helpful admissions.\" The partner needs to know which admission and what it unlocks. The key one: he conceded he never read the contract before signing.","task":"Write 2 sentences: the specific admission, then what it does for the case.","tips":["Quote or paraphrase the exact admission.","So-what: it guts their 'we relied on the terms' defense.","One load-bearing admission beats 'some helpful' ones."],"focus":["precision","impact"]},
    {"id":"precision-law-mid-13","level":"mid","profession":"lawyer","title":"'Industry standard' with no source","scenario":"You told the client the indemnity cap you're pushing is \"industry standard.\" Opposing counsel challenged it. You base it on the client's own last five deals and a market study — but your email didn't say so.","task":"Rewrite the claim so it's backed by a specific, citable basis.","tips":["'Industry standard' needs a source or it's just assertion.","Cite the client's own precedent deals — hardest to dispute.","A backed claim wins the negotiation; a bare one invites pushback."],"focus":["precision","clarity"]},
    {"id":"precision-law-mid-14","level":"mid","profession":"lawyer","title":"The vague budget update","scenario":"You tell the partner the matter is \"tracking roughly to budget, maybe a little over.\" She needs a number for the client. You're at $185K against a $200K budget with $40K of work left — so about $25K over.","task":"Rewrite with the specific spend, budget, and projected overage.","tips":["'A little over' becomes '$25K over, landing near $225K.'","Show spent, budgeted, and remaining.","Partners can manage a number; they can't manage a shrug."],"focus":["precision","impact"],"placeholder":"We're at $185K of the $200K budget with about $40K of work left — projecting roughly $225K, or $25K over."},
    {"id":"precision-law-mid-15","level":"mid","profession":"lawyer","title":"The intensifier-laden warning","scenario":"Your risk email says the exposure is \"extremely serious\" and the client \"absolutely must\" act \"immediately.\" The intensifiers do the work numbers should. The real facts: a 30-day statutory deadline and up to $500K in penalties.","task":"Rewrite the warning with the deadline and the penalty number instead of intensifiers.","tips":["'Extremely serious' becomes 'up to $500K in penalties.'","'Immediately' becomes 'within 30 days.'","Facts alarm more credibly than adjectives."],"focus":["precision","impact"]},
    {"id":"precision-law-mid-16","level":"mid","profession":"lawyer","title":"What / so what / now what for the ruling","scenario":"The court granted partial summary judgment against the client on one of four claims. Your email states the ruling but stops there. The client needs to know what it means and what to do.","task":"Write the ruling (what), its effect on the case (so what), and the next action (now what) in 3 sentences.","tips":["What: one claim dismissed, three survive.","So what: exposure drops, the core case continues.","Now what: the decision this forces — press settlement or proceed."],"focus":["precision","structure"]},
    {"id":"precision-law-mid-17","level":"mid","profession":"lawyer","title":"'Significant delay' in the notice","scenario":"You're drafting a breach notice citing the supplier's \"significant\" and \"repeated\" late deliveries. For the notice to bite, it needs the specific instances. There were 7 late shipments over 4 months, averaging 12 days late.","task":"Rewrite the allegation with the counts and the average delay.","tips":["'Significant and repeated' becomes '7 shipments, averaging 12 days late.'","Specifics make the notice defensible if challenged.","Vague allegations invite a vague denial."],"focus":["precision","clarity"],"placeholder":"Between January and April, 7 of your shipments arrived late, averaging 12 days past the delivery date."},
    {"id":"precision-law-mid-18","level":"mid","profession":"lawyer","title":"The skeptic-proof recommendation","scenario":"You recommend the client accept the deal because the risk of losing is \"just too high.\" A board member asks what specifically makes it high. Your real basis: an adverse document, a hostile venue, and a weak witness.","task":"Rewrite the recommendation so a skeptical board member can't dismiss it — name the three specific risk drivers.","tips":["'Too high' invites 'says who' — pre-empt it.","Three concrete drivers, each verifiable.","The board should leave unable to argue the premise, only the choice."],"focus":["precision","impact"]},
    {"id":"precision-law-mid-19","level":"mid","profession":"lawyer","title":"Quantifying the review burden","scenario":"You're justifying the discovery budget to the client and wrote that there are \"a lot of documents\" to review. The client wants the real scope. It's 1.2 million documents, cullable to about 180,000 for review.","task":"Rewrite with the document counts and what they mean for cost.","tips":["'A lot' becomes '1.2M, culled to 180K.'","Tie the count to the cost and timeline.","Scale justifies budget; vagueness invites suspicion."],"focus":["precision","impact"]},
    {"id":"precision-law-mid-20","level":"mid","profession":"lawyer","title":"The one metric for the compliance report","scenario":"Your compliance audit produced pages of findings. The GC asked for the headline number. The one that matters: 4 of 200 sampled transactions violated the policy — a 2% rate that the regulator treats as material above 1%.","task":"Write the one-sentence headline with the rate and why it crosses the line.","tips":["Lead with the number that triggers action: 2% against a 1% threshold.","Give the sample so the rate is credible.","One metric, framed against the standard, beats a page of findings."],"focus":["precision","impact"],"placeholder":"4 of 200 sampled transactions breached the policy — a 2% rate, above the 1% the regulator treats as material."},
    {"id":"precision-law-mid-21","level":"mid","profession":"lawyer","title":"'Reasonable' fees, made concrete","scenario":"You told the client the settlement includes \"a reasonable contribution to their legal fees.\" They want the number before they agree. It's $85K, about 40% of what the other side claims to have spent.","task":"Rewrite with the dollar figure and the context that makes it reasonable.","tips":["'Reasonable contribution' becomes '$85K.'","Anchor it: 40% of their claimed spend.","A number the client can weigh beats a comforting adjective."],"focus":["precision","clarity"]},
    {"id":"precision-law-mid-22","level":"mid","profession":"lawyer","title":"The evidence behind 'they knew'","scenario":"Your brief argues the defendant \"clearly knew\" about the defect. A skeptical reader asks how you know. Your basis: a specific internal email dated three weeks before the sale flagging the exact issue.","task":"Rewrite the assertion so it points to the specific evidence.","tips":["'Clearly knew' is conclusory; the email is proof.","Name the document, the date, and what it said.","Show the evidence and the conclusion writes itself."],"focus":["precision","clarity"]},
    {"id":"precision-law-mid-23","level":"mid","profession":"lawyer","title":"So-what for the regulatory change","scenario":"You flagged to the client that a new regulation \"may have implications\" for their operations. That's true of everything. The specific impact: their current data-retention practice becomes non-compliant, requiring a system change by year-end.","task":"Rewrite with the specific impact and the concrete action required.","tips":["'May have implications' says nothing — name the one that lands.","Tie it to their actual practice, not the abstract rule.","Now-what: the system change and the deadline."],"focus":["precision","impact"]},
    {"id":"precision-law-mid-24","level":"mid","profession":"lawyer","title":"The junior's unquantified claim","scenario":"A junior's memo says the opposing party's damages model is \"probably overstated.\" You're teaching precision. The model overstates by double-counting a $400K item and using a discount rate 3 points too low.","task":"Rewrite the junior's line to name the two specific flaws with numbers, and note the lesson.","tips":["'Probably overstated' becomes two named errors.","Quantify each: the double-counted $400K, the 3-point rate gap.","Lesson: a challenge sticks only when it's specific."],"focus":["precision","clarity"]},
    {"id":"precision-law-mid-25","level":"mid","profession":"lawyer","title":"The spoken risk number","scenario":"On a call, the CEO asks flatly: \"What are our odds if we go to trial?\" You tend to answer with 'it depends' and a discussion of variables. He wants a number he can act on.","task":"Give a spoken answer that leads with a probability range, then one caveat.","tips":["Lead with the number: 'roughly 60-40 in our favor.'","One caveat that could move it, then stop.","'It depends' is a non-answer; give the range and the hinge."],"focus":["precision","clarity"],"placeholder":"Roughly 60-40 in our favor — the swing factor is whether the judge lets the expert testify."}
  ],
  "executive-presence": [
    {"id":"presence-law-mid-01","level":"mid","profession":"lawyer","title":"The menu with no recommendation","scenario":"You've laid out three options for the client's contract dispute — litigate, mediate, renegotiate — with pros and cons of each, and stopped there. The GC replies: \"What do you actually think we should do?\" You do have a view: mediate.","task":"Rewrite the closing so you own a recommendation while keeping the options visible.","tips":["Present the menu, then plant your flag: 'I'd mediate.'","Give the one reason your pick beats the other two.","A neutral menu makes the client do your job."],"focus":["impact","clarity"],"placeholder":"Of the three, I'd mediate — it's the only path that resolves this before the launch and keeps the relationship intact."},
    {"id":"presence-law-mid-02","level":"mid","profession":"lawyer","title":"Fact versus judgment in the assessment","scenario":"Your case assessment blends what's certain with what you believe: \"The contract was breached and we'll clearly win.\" The breach is documented fact; the win is your judgment call at maybe 70%. Mixing them costs you credibility.","task":"Rewrite the assessment separating the established fact from your professional judgment.","tips":["Label what's fact — the breach, the dates — and state it flatly.","Label your judgment as judgment, with your confidence.","Blurring the two makes a partner distrust both."],"focus":["precision","clarity"]},
    {"id":"presence-law-mid-03","level":"mid","profession":"lawyer","title":"Signposting the client briefing","scenario":"You're about to brief the client's leadership on the litigation for ten minutes and tend to launch straight in. Without signposting, they lose track of where you are and interrupt.","task":"Write the 2-sentence opening that signposts the three things you'll cover and the decision you need.","tips":["Tell them the map before the journey: three points, one decision.","Name the decision up front so they listen for it.","Signposting reads as control of the material."],"focus":["structure","impact"],"placeholder":"I'll cover three things — where we stand, the risk, and the settlement window — and then ask you for one decision."},
    {"id":"presence-law-mid-04","level":"mid","profession":"lawyer","title":"Owning the settlement number","scenario":"You've analyzed the case and believe the client should authorize settlement up to $600K. Your draft hedges: \"you might consider a range somewhere in the vicinity of perhaps $500-700K.\" That's not advice; it's a shrug.","task":"Rewrite to own a specific recommended authority with your reasoning.","tips":["Name a number you'd defend: authorize up to $600K.","One line of why that's the right ceiling.","Clients hire you for a recommendation, not a range of shrugs."],"focus":["impact","precision"]},
    {"id":"presence-law-mid-05","level":"mid","profession":"lawyer","title":"The recommendation the partner will challenge","scenario":"You're recommending to the partner that the firm decline a matter on conflict-adjacent grounds. She'll push back — it's a big fee. You tend to soften recommendations you expect resistance to.","task":"State the recommendation with conviction in 2-3 sentences, ready to defend it.","tips":["Lead with your call, not with the caveats that fear it.","One clear reason, stated as a reason, not a worry.","Conviction invites a real debate; hedging invites dismissal."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-06","level":"mid","profession":"lawyer","title":"Presence on the client call","scenario":"On a call, the client asks whether they're exposed on the data issue. You know they are, moderately. You catch yourself starting with \"well, it's complicated, there are a lot of factors...\" — which reads as evasion.","task":"Script a confident 2-3 sentence spoken answer that gives the honest assessment plainly.","tips":["Start with the assessment: yes, moderate exposure.","Then the shape of it, briefly.","'It's complicated' sounds like you don't know — say what you do know."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-07","level":"mid","profession":"lawyer","title":"Standing behind the junior's work","scenario":"In a client meeting, the client questions a conclusion in a memo your junior drafted and you reviewed. You believe the conclusion is right. Deflecting to 'the associate drafted that' would undercut your team and your presence.","task":"Write a 2-sentence response that owns the conclusion and defends it on the merits.","tips":["Own it as the firm's advice, not the junior's.","Defend the substance, not the process.","Owning your team's work is a mark of presence."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-08","level":"mid","profession":"lawyer","title":"The board answer that lands","scenario":"You're presenting to the board on the regulatory investigation. A director asks if the company is in serious trouble. You tend to qualify heavily. The honest answer is: manageable, with one real risk, and here's the plan.","task":"Give a composed 3-sentence answer: the overall read, the one real risk, the plan.","tips":["Lead with the calm verdict: manageable.","Name the single real risk without burying it.","End on the plan — presence is showing you have one."],"focus":["impact","structure"],"placeholder":"Manageable, not a crisis. There's one real risk — the retention issue — and here's how we're handling it:"},
    {"id":"presence-law-mid-09","level":"mid","profession":"lawyer","title":"Judgment, clearly labeled","scenario":"Advising on whether to counter-sue, you write: \"a counterclaim would strengthen our position.\" Is that a fact about litigation dynamics or your judgment about this case? The partner needs to know which she's evaluating.","task":"Rewrite so your judgment is unmistakably owned as your view, with the reasoning.","tips":["'I recommend' or 'in my judgment' — claim the call.","Separate the general principle from your read of this case.","Owned judgment is stronger than disguised assertion."],"focus":["impact","precision"]},
    {"id":"presence-law-mid-10","level":"mid","profession":"lawyer","title":"The recommendation email to the GC","scenario":"You're emailing the GC on whether to appeal. Your draft presents the appellate landscape thoroughly and neutrally, then ends. She has to infer what you think. You believe they should not appeal.","task":"Add a clear recommendation up top and signpost the reasoning below it.","tips":["Recommendation first: do not appeal.","Then 'here's why, in two points' — signposted.","Landscape without a recommendation isn't advice."],"focus":["impact","structure"]},
    {"id":"presence-law-mid-11","level":"mid","profession":"lawyer","title":"Composure under the partner's fire","scenario":"In a strategy meeting the partner says your proposed approach is 'too cautious.' You still think it's right. Your instinct is to either cave or get defensive. Presence is holding your view while staying open.","task":"Script a 2-3 sentence response that holds your position without defensiveness.","tips":["Acknowledge the concern, don't absorb it.","Restate your reasoning, calmly and specifically.","Presence is a steady 'here's why I'd still do it,' not a retreat."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-12","level":"mid","profession":"lawyer","title":"The confident 'here's what I'd do'","scenario":"The client's COO asks how you'd handle the supplier who's threatening to walk. You have a clear plan but tend to present it as 'one option would be...' which drains the authority out of it.","task":"Rewrite as a direct 'here's what I'd do' with the two steps.","tips":["Own the plan: 'Here's what I'd do.'","Two concrete steps, in order.","'One option would be' sounds like you're browsing, not advising."],"focus":["impact","clarity"],"placeholder":"Here's what I'd do. First, send the formal cure notice today; second, open a quiet call to their GC by Friday."},
    {"id":"presence-law-mid-13","level":"mid","profession":"lawyer","title":"Fact and opinion in the deal memo","scenario":"Your deal memo says \"the indemnity is buyer-favorable and we should push back hard.\" The first half is an observation about the term; the second is your recommendation. Splicing them makes the recommendation look like a fact.","task":"Rewrite separating the observation from the recommendation, each clearly its own.","tips":["State what the term does — the observation.","Then 'I recommend pushing back' — the judgment.","Keeping them distinct lets the client weigh each."],"focus":["precision","clarity"]},
    {"id":"presence-law-mid-14","level":"mid","profession":"lawyer","title":"The one-slide recommendation","scenario":"You're giving the client a single slide on the litigation choice. Your draft lists considerations in bullets with no recommendation, so the room debates in circles. You believe they should settle now.","task":"Write the slide's title and one-line recommendation so it drives the decision, not a debate.","tips":["Make the title the recommendation, not the topic.","One line of rationale beneath.","A slide that recommends ends the meeting faster than one that lists."],"focus":["impact","structure"]},
    {"id":"presence-law-mid-15","level":"mid","profession":"lawyer","title":"Presence in the negotiation room","scenario":"Across the table, opposing counsel makes an aggressive demand and looks to you. You need to respond in a way that holds the room without escalating. You tend to either concede ground or match their tone.","task":"Script a 2-sentence response that holds firm and calm.","tips":["Calm restatement of your position beats a raised voice.","Don't fill silence with concessions.","Presence is being the steadiest person at the table."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-16","level":"mid","profession":"lawyer","title":"Owning a wrong call","scenario":"A strategy you recommended didn't pan out — the motion you pushed for was denied. In the debrief with the partner, deflecting or over-apologizing both hurt your standing. Presence is owning it and pivoting to the fix.","task":"Write a 2-3 sentence debrief line that owns the call and moves to the next step.","tips":["Name it plainly: 'my read on the judge was wrong.'","No spiral, no excuses — one clean acknowledgment.","Pivot fast to what you'd do now; that's the presence."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-17","level":"mid","profession":"lawyer","title":"The recommendation the client won't like","scenario":"You believe the client should walk away from a deal they're emotionally invested in — the numbers don't work legally. You tend to bury unwelcome recommendations. Presence is delivering it clearly and standing behind it.","task":"State the recommendation in 2-3 sentences with the conviction to hold it under pushback.","tips":["Say it plainly: I'd walk.","Give the reason that would survive their objection.","A recommendation you won't defend isn't worth giving."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-18","level":"mid","profession":"lawyer","title":"Signposting a dense answer","scenario":"The client asks a genuinely complex question about their liability across three contracts. You could ramble. Presence is structuring the answer out loud so they can follow, even under complexity.","task":"Write the opening that signposts the three contracts you'll address, then the lead line for the first.","tips":["'There are three contracts; let me take them in order.'","Signpost, then deliver — the map keeps them with you.","Structure under complexity is what presence looks like."],"focus":["structure","impact"]},
    {"id":"presence-law-mid-19","level":"mid","profession":"lawyer","title":"The steady status in a crisis","scenario":"A subpoena arrived unexpectedly and the client's leadership is rattled on the call. They're looking to you to set the tone. Panic or over-reassurance both undercut you. Presence is calm command of the facts and the plan.","task":"Script a 3-sentence opening that steadies the room with facts and a plan.","tips":["Name what happened factually, without alarm.","State that there's a clear response and you're executing it.","Your composure sets theirs — be the calm."],"focus":["impact","clarity"],"placeholder":"Here's exactly what arrived and what it means. This is serious but routine, and we have a clear response — let me walk you through it."},
    {"id":"presence-law-mid-20","level":"mid","profession":"lawyer","title":"Recommendation over recitation","scenario":"The partner asks what you'd do about the discovery dispute. Your draft recites the procedural options available. She wants your judgment, not a treatise. You'd file the motion to compel.","task":"Rewrite to lead with your recommendation, using the options only as brief support.","tips":["Lead: 'I'd file the motion to compel.'","Options become the one-line 'versus' behind your pick.","Recitation is what a search engine does; you're paid for judgment."],"focus":["impact","concision"]},
    {"id":"presence-law-mid-21","level":"mid","profession":"lawyer","title":"Holding a position with the CFO","scenario":"The client's CFO wants to cut the litigation budget mid-case in a way you think will cost them the case. You need to push back with authority, not just object. You have a clear view on which cuts are fatal.","task":"Write a 2-3 sentence response that holds the line and gives him a real choice.","tips":["Respect the constraint; name what the cut actually costs.","Offer the smart trim versus the fatal one.","Presence is disagreeing usefully, not just resisting."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-22","level":"mid","profession":"lawyer","title":"The judgment call, stated as one","scenario":"On whether a clause is enforceable, the honest answer is a close judgment call. You tend to either overstate confidence or hide behind 'it depends.' Presence is naming it as a close call and still giving your lean.","task":"Write a 2-3 sentence answer that owns the uncertainty and still commits to a lean.","tips":["Say it's a close call — that's honest and confident at once.","Then give your lean and why.","'It could go either way' with no lean is an abdication."],"focus":["impact","precision"],"placeholder":"This is a close call, but I lean enforceable — the tailoring here is exactly what the recent cases reward."},
    {"id":"presence-law-mid-23","level":"mid","profession":"lawyer","title":"The recommendation in the subject line","scenario":"You're emailing the client a recommendation to accept a settlement. Your subject line reads 'Settlement Update.' The recommendation itself is presence — putting it where they'll see it first shows you stand behind it.","task":"Write a subject line and opening sentence that both carry the recommendation.","tips":["Subject line states the recommendation, not the topic.","Opening sentence repeats and owns it.","Where you put your recommendation signals how much you back it."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-24","level":"mid","profession":"lawyer","title":"Composed under a hostile question","scenario":"In a client meeting a new executive challenges your competence: \"Have you actually handled a case like this before?\" You have. Presence is answering with quiet confidence, not defensiveness or over-selling.","task":"Script a 2-sentence response that answers with grounded confidence.","tips":["Answer the question factually and briefly.","Let the specifics carry the confidence, not your tone.","Neither defensive nor boastful — just steady."],"focus":["impact","clarity"]},
    {"id":"presence-law-mid-25","level":"mid","profession":"lawyer","title":"The decisive close","scenario":"You've walked the client through a complex analysis and now need to close with a clear recommendation and next step. You tend to trail off into 'so, those are the considerations...' which leaves them adrift.","task":"Write a 2-sentence close that states the recommendation and the next action.","tips":["End with a recommendation, not a summary of considerations.","Name the next action and who owns it.","A decisive close is where presence is remembered."],"focus":["impact","structure"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-law-mid-01","level":"mid","profession":"lawyer","title":"The question behind the question","scenario":"On a call, the client's CEO asks: \"Why is this taking so long?\" The real question is whether you're on top of it. Your instinct is to defend the timeline point by point, which sounds defensive.","task":"Answer the actual question first in 2-3 sentences, then address the timeline.","tips":["The real question is 'are we in control?' — answer that first.","Then the honest timeline driver, without a defensive list.","Defensiveness confirms the fear; calm ownership dispels it."],"focus":["clarity","impact"]},
    {"id":"pressure-law-mid-02","level":"mid","profession":"lawyer","title":"The 'I don't know' with a path","scenario":"In a client meeting, the GC asks how a specific judge tends to rule on a motion like yours. You genuinely don't know that judge's tendencies yet. Bluffing is dangerous; a bare 'I don't know' is weak.","task":"Give an honest 'I don't know' that includes how and when you'll find out.","tips":["Say you don't know — cleanly, no waffle.","Name how you'll find out: pull the judge's recent rulings.","Give a when, so it's a plan, not a dead end."],"focus":["clarity","precision"],"placeholder":"I don't know this judge's pattern yet, but I'll pull her last two years of rulings on this and have a read by Thursday."},
    {"id":"pressure-law-mid-03","level":"mid","profession":"lawyer","title":"Pushback on your fee estimate","scenario":"The client's CFO challenges: \"Your estimate was $200K and now it's $260K — how do I trust any number you give me?\" You need to answer the trust question with specifics, not apologies.","task":"Respond in 3 sentences that answer the trust concern with a concrete cause and a fix.","tips":["Address trust directly — that's the real question.","Give the specific driver of the overrun, not a general mea culpa.","Offer the mechanism that prevents the next surprise."],"focus":["precision","impact"]},
    {"id":"pressure-law-mid-04","level":"mid","profession":"lawyer","title":"The partner's rapid-fire question","scenario":"The partner catches you off guard: \"Is our expert going to survive the Daubert challenge?\" You have concerns but haven't finished the analysis. You tend to either overstate confidence or dump every worry.","task":"Give a composed answer that states your current read honestly and the one thing that'll settle it.","tips":["Give your current lean, flagged as preliminary.","Name the single factor that decides it.","Don't dump all your worries — name the one that matters."],"focus":["clarity","precision"]},
    {"id":"pressure-law-mid-05","level":"mid","profession":"lawyer","title":"The hostile question in mediation","scenario":"In a joint mediation session, opposing counsel demands: \"Can your client even prove they suffered any real damages?\" It's meant to rattle you in front of the mediator. You can prove damages, specifically.","task":"Answer the actual challenge with a specific, calm response in 2-3 sentences.","tips":["Don't take the bait's tone; take its substance.","Name the specific proof — the invoices, the lost contract.","Calm specifics in front of the mediator do more than indignation."],"focus":["clarity","impact"]},
    {"id":"pressure-law-mid-06","level":"mid","profession":"lawyer","title":"The client who wants a guarantee","scenario":"The client presses: \"So we'll definitely win, right?\" You can't guarantee that and shouldn't. But 'no guarantees' alone sounds evasive. You need to answer honestly while conveying real confidence.","task":"Respond in 2-3 sentences that decline the guarantee but give a grounded confidence read.","tips":["No honest lawyer guarantees — say so, briefly.","Then give the real number and why it's strong.","Honest confidence beats a promise you can't keep."],"focus":["clarity","precision"],"placeholder":"No one can guarantee a verdict, and I won't. But this is a strong case — I'd put us at 70% on the facts we've locked down."},
    {"id":"pressure-law-mid-07","level":"mid","profession":"lawyer","title":"Answering for the missed issue","scenario":"In a review meeting, the partner asks why your team's diligence missed a lien that surfaced later. You did miss it. Defensiveness or blame-shifting both fail. Ownership plus the systemic fix is the answer.","task":"Write a 2-3 sentence response that owns the miss and names the process fix.","tips":["Own it without a spiral or an excuse.","Explain what let it slip — briefly, factually.","Lead to the fix so it doesn't recur — that's what she needs."],"focus":["clarity","impact"]},
    {"id":"pressure-law-mid-08","level":"mid","profession":"lawyer","title":"The redirect that isn't evasion","scenario":"The client asks a detailed question about a side issue while the meeting's real purpose — the settlement decision — goes untouched with ten minutes left. You need to answer briefly and steer back without seeming evasive.","task":"Write a 2-3 sentence response that answers the side question briefly and redirects to the decision.","tips":["Answer the question — don't dodge it — but tightly.","Name why the decision needs the remaining time.","Redirect openly: 'and the bigger thing we need to land today is...'"],"focus":["clarity","structure"]},
    {"id":"pressure-law-mid-09","level":"mid","profession":"lawyer","title":"When the client challenges your advice","scenario":"You advised against a clause; the client's business lead snaps: \"Our last firm let us do this all the time — why won't you?\" You need to hold your position with a specific reason, not defensiveness.","task":"Respond in 2-3 sentences that hold the line with a concrete reason, not a turf defense.","tips":["Don't relitigate the other firm; address the risk.","Give the specific harm the clause invites.","Offer the safer path so it's not just a 'no.'"],"focus":["clarity","impact"]},
    {"id":"pressure-law-mid-10","level":"mid","profession":"lawyer","title":"The 'yes or no' you can't fully answer","scenario":"The board member demands: \"Are we going to be sued — yes or no?\" The honest answer is 'probably, but' — and the 'but' matters. You need to give the yes/no without losing the essential nuance.","task":"Answer the yes/no first, then the one piece of nuance that changes the picture.","tips":["Lead with the direct answer they demanded.","One sentence of the nuance that matters most.","Answer first earns you the right to add the 'but.'"],"focus":["clarity","precision"]},
    {"id":"pressure-law-mid-11","level":"mid","profession":"lawyer","title":"The deposition-style pressure from a client","scenario":"A frustrated client fires three questions at once: \"When does discovery end, why haven't they produced the emails, and are we going to trial?\" You need to answer all three without scrambling.","task":"Answer the three questions in order, one crisp sentence each.","tips":["Take them in order; don't let the volume rattle you.","One clean sentence per question — no merging.","Structured calm under a barrage is the whole skill."],"focus":["structure","clarity"]},
    {"id":"pressure-law-mid-12","level":"mid","profession":"lawyer","title":"The partner questions your strategy publicly","scenario":"In a client meeting, the partner unexpectedly questions your recommended strategy in front of the client. You still believe it's right. You need to respond respectfully without caving or creating a visible rift.","task":"Write a 2-3 sentence response that holds your reasoning while respecting the partner.","tips":["Acknowledge the partner's point genuinely.","Restate your reasoning as a contribution, not a rebuttal.","Present a united front while keeping your substance."],"focus":["clarity","impact"]},
    {"id":"pressure-law-mid-13","level":"mid","profession":"lawyer","title":"The honest unknown on exposure","scenario":"The CFO asks for a firm exposure number for the annual report. You can give a range but not a point estimate — the case is too early. Pressure to name a single number is real, but a false precision would be worse.","task":"Respond in 2-3 sentences giving the honest range and why a single number isn't yet responsible.","tips":["Give the range you'd stand behind.","Explain why point precision would be false now.","Name when you'll be able to narrow it."],"focus":["precision","clarity"]},
    {"id":"pressure-law-mid-14","level":"mid","profession":"lawyer","title":"The accusatory 'why didn't you'","scenario":"The client asks: \"Why didn't you warn us this could happen?\" You did, in a memo six months ago that they didn't act on. You need to answer without sounding like you're saying 'I told you so.'","task":"Write a 2-3 sentence response that notes the earlier advice factually and pivots to the fix.","tips":["Reference the prior advice as fact, not vindication.","Don't linger on who was warned — pivot to now.","The useful answer is 'here's what we do from here.'"],"focus":["clarity","impact"]},
    {"id":"pressure-law-mid-15","level":"mid","profession":"lawyer","title":"The trick question from opposing counsel","scenario":"On a scheduling call, opposing counsel slips in: \"So you'll agree your client had notice of the defect by January, right?\" It's a fact-conceding trap dressed as logistics. You can't concede it.","task":"Respond in 1-2 sentences that decline the concession without being drawn into argument.","tips":["Spot the trap; don't answer the loaded premise.","Decline cleanly: that's a merits question for the record, not this call.","Return to the actual scheduling purpose."],"focus":["clarity","precision"]},
    {"id":"pressure-law-mid-16","level":"mid","profession":"lawyer","title":"When you're asked to speculate","scenario":"The client's CEO asks what the other side is 'really thinking' about settlement. You can offer an informed read but must flag it as inference, not fact. Under pressure to sound authoritative, over-claiming is the risk.","task":"Give your read in 2-3 sentences, clearly labeled as inference with its basis.","tips":["Offer the read, flagged as inference.","Name what it's based on — their last three moves.","Confident inference beats a false claim of knowledge."],"focus":["precision","clarity"]},
    {"id":"pressure-law-mid-17","level":"mid","profession":"lawyer","title":"The budget-cut ultimatum","scenario":"The client says flatly: \"Cut the fees by 30% or we go elsewhere.\" You need to respond in the moment without either caving reflexively or losing the client. There's real room on some tasks, none on others.","task":"Respond in 2-3 sentences that engage the demand with specifics, not a flat yes or no.","tips":["Don't answer the ultimatum with an ultimatum.","Name where you can flex and where the cut costs them.","Turn a threat into a scoping conversation."],"focus":["impact","clarity"]},
    {"id":"pressure-law-mid-18","level":"mid","profession":"lawyer","title":"The junior's question you can't answer yet","scenario":"A junior asks in front of the team whether a novel argument you floated will actually work. You're not sure yet — it's untested. Modeling honest uncertainty is better than false authority.","task":"Answer in 2-3 sentences that model honest uncertainty and a way to resolve it.","tips":["Say you're not sure — it's the honest answer.","Name how you'll pressure-test it: research, a moot.","Modeling 'I don't know yet, here's how we find out' teaches more than bluffing."],"focus":["clarity","precision"]},
    {"id":"pressure-law-mid-19","level":"mid","profession":"lawyer","title":"The regulator's pointed question","scenario":"In a call with the state regulator, the examiner asks whether the client's disclosures were compliant during the period in question. The honest answer is partly — one disclosure fell short. You must answer candidly without over-conceding.","task":"Craft a 2-3 sentence response that is candid about the shortfall without volunteering more than asked.","tips":["Answer the question asked — candidly, precisely.","Acknowledge the one shortfall; don't editorialize on it.","Candor without over-disclosure protects the client and your credibility."],"focus":["precision","clarity"]},
    {"id":"pressure-law-mid-20","level":"mid","profession":"lawyer","title":"The 'give me the bottom line' interruption","scenario":"You're mid-explanation when the client cuts in: \"I don't need the analysis, just tell me — can we do this or not?\" Under pressure you tend to keep explaining. They want the verdict now.","task":"Give the bottom-line verdict in one sentence, then offer the reasoning only if they want it.","tips":["Give the yes/no immediately — they asked for it.","Offer, don't impose, the reasoning: 'happy to walk the why if useful.'","Reading the room means dropping the buildup when told to."],"focus":["concision","clarity"],"placeholder":"Yes, you can do it. Want the two conditions, or is the yes enough for now?"},
    {"id":"pressure-law-mid-21","level":"mid","profession":"lawyer","title":"Challenged on a cited case","scenario":"In a hearing prep session, the partner challenges: \"Are you sure that case still holds — hasn't it been distinguished?\" You believe it holds but aren't 100% certain of the latest treatment. Bluffing here could be fatal at the hearing.","task":"Respond in 2-3 sentences that give your honest confidence and commit to confirming before the hearing.","tips":["State your current confidence honestly.","Never bluff on authority — commit to verifying.","Give the when: 'I'll shepardize it and confirm by end of day.'"],"focus":["precision","clarity"]},
    {"id":"pressure-law-mid-22","level":"mid","profession":"lawyer","title":"The client's 'just make it go away'","scenario":"The frustrated client says: \"I don't care how, just make this lawsuit disappear.\" You can't make it vanish, and pretending you can sets a trap. You need to reset expectations without deflating them.","task":"Respond in 2-3 sentences that reset the expectation honestly and offer the realistic fastest path.","tips":["Don't promise the impossible to please them.","Reframe 'disappear' into the fastest realistic resolution.","Give them a concrete path to hold onto."],"focus":["clarity","impact"]},
    {"id":"pressure-law-mid-23","level":"mid","profession":"lawyer","title":"The surprise question in the board room","scenario":"You're presenting on one matter when a director pivots: \"And what's our overall legal risk across the whole company?\" You weren't prepped for the portfolio view. You have a rough sense but not chapter and verse.","task":"Give a composed 2-3 sentence answer that offers your high-level read and offers to follow up with detail.","tips":["Give the honest high-level read you do have.","Flag it as high-level, not the full picture.","Offer a proper follow-up rather than winging specifics."],"focus":["clarity","structure"]},
    {"id":"pressure-law-mid-24","level":"mid","profession":"lawyer","title":"When your own number is challenged","scenario":"You recommended settling at $700K; the client's CFO retorts: \"Where did $700K even come from? That seems high.\" You have a defensible basis. Under the challenge, you need to show your work calmly.","task":"Respond in 2-3 sentences that walk the basis for the number without defensiveness.","tips":["Show the work: what drives the $700K.","Anchor to comparables or the expected trial value.","Calm math answers a challenge better than a raised voice."],"focus":["precision","impact"]},
    {"id":"pressure-law-mid-25","level":"mid","profession":"lawyer","title":"The rapid escalation on a call","scenario":"A routine client call escalates when the CEO learns of an adverse development for the first time and demands to know 'what you're going to do about it' immediately. You need to absorb the heat and give a steady, structured answer.","task":"Script a 3-sentence response that acknowledges, steadies, and lays out the immediate next step.","tips":["Acknowledge the development plainly — don't minimize.","Steady the room: this is manageable and here's why.","Give the one immediate next step so it's a plan, not a panic."],"focus":["impact","structure"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-law-mid-01","level":"mid","profession":"lawyer","title":"The before/after in the settlement pitch","scenario":"You're persuading the client to accept a settlement. Your draft lists the settlement's terms neutrally. It would land harder framed as a change: the uncertainty and cost they live in now, versus the closure the deal buys.","task":"Rewrite the pitch to frame the before (litigation limbo) and after (certainty) of accepting.","tips":["Paint 'now': open exposure, mounting fees, distraction.","Paint 'after': a known number, closed book, team refocused.","The contrast persuades more than a list of terms."],"focus":["impact","clarity"],"placeholder":"Right now you're carrying an open-ended risk and a legal bill that grows every month. This deal trades all of that for one known number and a closed file."},
    {"id":"narrative-law-mid-02","level":"mid","profession":"lawyer","title":"Concrete stakes for the compliance ask","scenario":"You're asking the business team to invest in a compliance overhaul they see as bureaucratic. Your draft cites regulations. It would persuade more with the concrete stake: what a violation actually costs this company.","task":"Rewrite the ask to make the stakes concrete and specific to them.","tips":["Turn the abstract regulation into their number: the fine, the shutdown risk.","Use a real, recent example from their industry.","Concrete stakes move budgets; citations don't."],"focus":["impact","precision"]},
    {"id":"narrative-law-mid-03","level":"mid","profession":"lawyer","title":"Pre-empting the client's objection","scenario":"You're recommending they fight the claim rather than settle. You know the client's strongest objection: the cost of litigation. Your draft ignores it and hopes it won't come up. It will.","task":"Rewrite the recommendation to raise and answer the cost objection before they do.","tips":["Name their objection out loud — it builds trust.","Answer it with the counter-math: cost versus the settlement demand.","Pre-empting the strongest objection is more persuasive than dodging it."],"focus":["impact","structure"]},
    {"id":"narrative-law-mid-04","level":"mid","profession":"lawyer","title":"The demand letter's story","scenario":"Your demand letter lists the contract breaches in clause order. A persuasive demand tells a story: a partner the client trusted, who took the money and walked. Opposing counsel and any future judge respond to the narrative, not just the list.","task":"Rewrite the opening as a 3-4 sentence narrative of what happened, in plain human terms.","tips":["Tell it as a story: trust given, trust broken, harm done.","Chronology and human stakes, not clause numbers.","A story frames the breaches; the list only catalogs them."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-05","level":"mid","profession":"lawyer","title":"Persuading the partner to take the case a new way","scenario":"You want the partner to pursue an aggressive counterclaim strategy she's skeptical of. Your draft leads with the legal theory. It would land better framed as the change it creates: from defending on the back foot to controlling the terms.","task":"Rewrite the pitch to frame the strategic shift it creates, then support with the theory.","tips":["Lead with the shift: from reacting to setting the agenda.","Make the current 'before' state vivid — always responding.","Theory supports the story; it shouldn't lead it."],"focus":["impact","structure"]},
    {"id":"narrative-law-mid-06","level":"mid","profession":"lawyer","title":"Stakes for the litigation-hold reluctance","scenario":"IT is dragging on the litigation hold, seeing it as an inconvenience. Your reminder cites preservation duties. It would move them if they understood the stake: a spoliation sanction that could lose the case outright.","task":"Rewrite the message to make the stake of non-compliance concrete for IT.","tips":["Name what deletion actually risks: losing the case, not a policy slap.","Use a plain example of a spoliation sanction.","The stake, made concrete, turns a chore into a priority."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-07","level":"mid","profession":"lawyer","title":"The persuasive case for mediation","scenario":"You want the reluctant client to try mediation. Your draft lists mediation's procedural features. Persuasion means framing the choice: keep bleeding time and money on a fight nobody's winning, or take a structured shot at ending it.","task":"Rewrite as a 3-sentence persuasive frame contrasting the current path with mediation.","tips":["Contrast the paths: the grinding fight versus a real chance to end it.","Make the current cost vivid and specific.","Frame mediation as control regained, not surrender."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-08","level":"mid","profession":"lawyer","title":"Pre-empting the CFO's cost objection","scenario":"You're recommending the client hire a second expert witness — an expense. The CFO will object on cost. Your draft doesn't address it. Pre-empting the objection with the cost-of-not-doing-it would strengthen the ask.","task":"Rewrite the recommendation to name the cost objection and answer it with the downside of skipping.","tips":["Raise the cost concern before the CFO does.","Answer with the bigger cost: what a weak damages case loses at trial.","The expert is cheap against the exposure — make that math visible."],"focus":["impact","precision"]},
    {"id":"narrative-law-mid-09","level":"mid","profession":"lawyer","title":"The client alert that motivates action","scenario":"Your client alert about a new regulation reads like a summary of the law. Clients skim and file it. Reframed around what changes for them — and what happens if they don't act — it would actually drive them to call you.","task":"Rewrite the alert's core in 3 sentences framing the change and the stakes of inaction.","tips":["Frame it as a change to their world, not a legal update.","Make the cost of ignoring it concrete.","End with the action that closes the gap."],"focus":["impact","audience"]},
    {"id":"narrative-law-mid-10","level":"mid","profession":"lawyer","title":"Persuading the board to settle","scenario":"You're recommending the board authorize settlement. Some directors want to 'fight on principle.' Your draft is analytical. It needs a narrative that honors the principle while showing why settling serves it better.","task":"Write a 3-4 sentence persuasive frame that acknowledges the principle and reframes settling as the stronger stand.","tips":["Honor the instinct to fight — don't dismiss it.","Reframe: the principle is protected by resolving, not by risking a public loss.","Give the concrete stake of the fight-on path."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-11","level":"mid","profession":"lawyer","title":"The story behind the redline","scenario":"You're explaining to the business team why you're pushing back hard on an indemnity clause. Your draft is technical. A short story — 'here's the exact scenario where this clause bankrupts a deal like ours' — would persuade them to back you.","task":"Write a 3-sentence scenario that shows the clause causing real harm.","tips":["Tell the concrete failure story, start to finish.","Use their kind of deal, their kind of loss.","A vivid scenario persuades where clause analysis bores."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-12","level":"mid","profession":"lawyer","title":"Framing the fee increase","scenario":"You need to persuade the client to accept a higher fee for the expanded scope. Your draft justifies the rate. It would land better framing the before/after: the narrow engagement they signed versus the real fight it became.","task":"Rewrite the justification to frame how the matter changed, then the fee as fitting the new reality.","tips":["Show the change: what they hired you for versus what it became.","The fee follows the scope story, not the other way around.","Anchor to the value at stake now, not the original estimate."],"focus":["impact","precision"]},
    {"id":"narrative-law-mid-13","level":"mid","profession":"lawyer","title":"Pre-empting the 'other firm' objection","scenario":"You're recommending a conservative approach; you know the client will say 'our old firm was more aggressive.' Your draft ignores this. Naming and answering it — why aggressive cost them last time — would strengthen your position.","task":"Rewrite to pre-empt the 'old firm was bolder' objection with a concrete reason your approach serves them.","tips":["Raise the comparison yourself, neutrally.","Answer with the stake: aggressive here invites the counterclaim.","Reframe conservative as strategic, not timid."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-14","level":"mid","profession":"lawyer","title":"The persuasive internal-investigation update","scenario":"You're updating the audit committee on an internal investigation. Your draft is a neutral status. The committee needs to feel the stakes — reputational and regulatory — to authorize the resources the next phase needs.","task":"Write a 3-sentence update that frames the stakes concretely enough to justify the next-phase ask.","tips":["Make the stake concrete: what surfaces if this isn't done right.","Connect the resource ask to the risk it retires.","Persuasion here is showing why half-measures cost more."],"focus":["impact","structure"]},
    {"id":"narrative-law-mid-15","level":"mid","profession":"lawyer","title":"Making the damages real","scenario":"You're arguing damages to opposing counsel in settlement talks. Your draft states the number. It persuades more to tell the story of how the harm accumulated — the lost contract, the layoffs, the reputational hit — that adds up to it.","task":"Write a 3-4 sentence narrative of the harm that makes the damages number feel earned.","tips":["Tell the harm as a sequence, not a total.","Name the human and business consequences.","A number backed by a story is harder to discount."],"focus":["impact","precision"]},
    {"id":"narrative-law-mid-16","level":"mid","profession":"lawyer","title":"Persuading the client to preserve the relationship","scenario":"The client wants to sue a long-term supplier over a dispute you think is better resolved commercially. Your draft is legalistic. Framing the choice — a lawsuit that ends a valuable relationship versus a negotiated fix — would persuade.","task":"Write a 3-sentence frame contrasting the litigation path with the negotiated one, in business terms.","tips":["Frame the real tradeoff: a win that costs the relationship.","Make the value of the relationship concrete.","Give them the path that gets the fix without the rupture."],"focus":["impact","audience"]},
    {"id":"narrative-law-mid-17","level":"mid","profession":"lawyer","title":"The pitch to change tactics","scenario":"You want the partner to drop a losing motion and redirect to settlement. She's invested in the motion. Your draft leads with why the motion fails. It would persuade better framed as the shift from a sunk fight to a winnable position.","task":"Write a 3-sentence persuasive frame that redirects without relitigating the sunk cost.","tips":["Don't argue the motion is bad — argue the path forward is better.","Frame the shift: from a fight we're losing to leverage we can use.","Acknowledge the investment, then point past it."],"focus":["impact","structure"]},
    {"id":"narrative-law-mid-18","level":"mid","profession":"lawyer","title":"Concrete stakes for the privacy fix","scenario":"You're pushing the engineering team to prioritize a privacy remediation they see as low-urgency. Your draft cites the statute. Framing the stake — the specific breach scenario and its fine — would move it up their queue.","task":"Rewrite to make the stake concrete: the scenario and its cost.","tips":["Paint the specific failure, not the general obligation.","Attach the number: the fine, the notification cost, the churn.","Concrete downside beats abstract compliance every time."],"focus":["impact","precision"]},
    {"id":"narrative-law-mid-19","level":"mid","profession":"lawyer","title":"Pre-empting the settlement skeptic","scenario":"You're recommending settlement to a client who'll object that it 'rewards' the other side. Your draft doesn't address the fairness objection. Naming and reframing it would strengthen the persuasion.","task":"Rewrite to raise the 'this rewards them' objection and reframe it around the client's actual interest.","tips":["Name the fairness objection — it's real and felt.","Reframe: this isn't about them, it's about your risk and time.","Redirect from justice to the client's own math."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-20","level":"mid","profession":"lawyer","title":"The narrative for the injunction motion","scenario":"You're helping draft the story for a preliminary injunction. The legal standard needs irreparable harm. Your draft recites the factors. The judge needs to feel the harm — the market position lost daily that money can't restore.","task":"Write a 3-4 sentence narrative of the ongoing harm that makes 'irreparable' vivid.","tips":["Show harm happening now, not a legal category.","Make clear why money later can't undo it.","Judges grant on felt urgency, not factor recitation."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-21","level":"mid","profession":"lawyer","title":"Persuading the client to take the deal now","scenario":"A good settlement offer expires Friday; the client is inclined to wait for 'more.' Your draft lists reasons to accept. Framing the change — this window versus the uncertain, costlier path after it closes — would persuade them to move.","task":"Write a 3-sentence frame contrasting acting now with the path if the window closes.","tips":["Make the closing window concrete and real.","Contrast the certain good outcome with the uncertain later one.","Frame waiting as the risk, not the safe choice."],"focus":["impact","clarity"],"placeholder":"This offer is on the table until Friday and it's a strong one. Wait, and you're back to an open-ended fight with no guarantee the number improves — and good odds it gets worse."},
    {"id":"narrative-law-mid-22","level":"mid","profession":"lawyer","title":"The persuasive scope-of-work note","scenario":"You're proposing a broader engagement to a cost-conscious client. Your draft lists services. It would persuade framed as the change: the exposure they carry unmanaged now versus the protection the fuller scope provides.","task":"Rewrite to frame the before/after of the broader engagement, with a concrete risk it retires.","tips":["Frame the current unmanaged risk vividly.","Show what the fuller scope specifically prevents.","Value, not a service list, justifies the spend."],"focus":["impact","audience"]},
    {"id":"narrative-law-mid-23","level":"mid","profession":"lawyer","title":"Pre-empting the objection to your witness plan","scenario":"You want to call the client's own CEO as a witness; the client resists exposing him. Your draft argues the legal benefit. Naming their real fear — a rough cross-examination — and answering it would persuade.","task":"Rewrite to raise the cross-examination fear and answer it with your preparation plan.","tips":["Name the fear directly: cross will be uncomfortable.","Answer with the concrete prep that manages it.","Addressing the fear beats pretending it isn't there."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-24","level":"mid","profession":"lawyer","title":"The story for the sympathetic facts","scenario":"Your client's case has strong sympathetic facts that your draft brief buries under doctrine. In a persuasive brief, the human story should frame the legal argument — the small business crushed by a giant's bad-faith tactics.","task":"Write a 3-4 sentence opening that leads with the human story before the legal frame.","tips":["Open on the people and the stakes, not the statute.","Let the sympathy set up the legal argument.","Doctrine convinces; story moves — lead with the mover."],"focus":["impact","clarity"]},
    {"id":"narrative-law-mid-25","level":"mid","profession":"lawyer","title":"The spoken pitch to settle","scenario":"On a call, you have two minutes to persuade the client to authorize settlement. You tend to walk through the analysis linearly. A persuasive spoken pitch frames the choice as a change and pre-empts their one objection.","task":"Script a 3-4 sentence spoken pitch: the before/after frame plus a pre-empted objection.","tips":["Open with the change: what settling ends versus what fighting prolongs.","Pre-empt their objection in one line — cost, or principle.","Close on the decision, not the analysis."],"focus":["impact","structure"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-law-mid-01","level":"mid","profession":"lawyer","title":"The case is weaker than they think","scenario":"The client believes they have a slam-dunk case. Your analysis says it's a coin flip at best. Your draft eases in with reassurance before the reality. Clear is kind: they're making decisions on a false premise.","task":"Write a 3-sentence message that front-loads the honest assessment without cushioning it into vagueness.","tips":["Lead with the hard truth: this is closer than you think.","Give the specific reason it's not a slam dunk.","Cushioning it now costs them worse later."],"focus":["clarity","impact"],"placeholder":"I need to reset expectations: this case is a coin flip, not the sure thing it looks like."},
    {"id":"hard-law-mid-02","level":"mid","profession":"lawyer","title":"The clean 'no' to the client's request","scenario":"The client wants you to send an aggressive threatening letter you believe would backfire legally and reputationally. You need to decline clearly. Your draft hedges with 'we could, but...' which leaves the door open.","task":"Write a clear 'no' with the reason, in 2-3 sentences, that doesn't reopen the debate.","tips":["Say no plainly — not 'we could but.'","Give the reason once, then stop.","A clean no respects them more than a reluctant maybe."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-03","level":"mid","profession":"lawyer","title":"Feedback on the junior's persistent error","scenario":"A junior keeps submitting drafts with the same citation-format errors despite prior correction. You need to give feedback that names the behavior, its impact, and asks for the change — not a vague 'be more careful.'","task":"Write 3 sentences: the specific behavior, its impact, and the concrete ask.","tips":["Name the behavior specifically, not 'sloppiness.'","State the impact: the partner's time, the firm's credibility.","Make the ask concrete and checkable."],"focus":["clarity","precision"]},
    {"id":"hard-law-mid-04","level":"mid","profession":"lawyer","title":"Telling the partner the deadline will slip","scenario":"You won't make the brief-filing deadline the partner promised the client, due to a document dump from the other side. You need to tell her now. Your draft opens with the document dump saga before the bad news.","task":"Write a 2-3 sentence message that leads with the slip and the ask.","tips":["Front-load it: we won't make Friday.","One line on why, then the fix — an extension motion.","Early bad news is a problem; late bad news is a crisis."],"focus":["clarity","impact"],"placeholder":"We won't make Friday's filing deadline — their document dump landed 40,000 pages on us Tuesday."},
    {"id":"hard-law-mid-05","level":"mid","profession":"lawyer","title":"The billing correction to the client","scenario":"You over-billed the client last month due to a coding error — about $12K. You need to tell them and correct it before they notice. Your draft buries the admission in a long explanation of billing systems.","task":"Write a 2-3 sentence message that leads with the error and the correction.","tips":["Front-load the error and the number.","State the correction plainly — credit applied.","Owning it fast builds more trust than a system explanation."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-06","level":"mid","profession":"lawyer","title":"Declining the partner's staffing request","scenario":"The partner wants you to take on a new matter, but you're already at capacity on two trials. Saying yes would sink all three. You need to decline clearly while showing you understand the need.","task":"Write a 2-3 sentence 'no' that's clear, respectful, and offers a path.","tips":["Decline clearly: I can't take this on well right now.","Show the tradeoff honestly — what would suffer.","Offer the alternative: a different associate, or a delayed start."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-07","level":"mid","profession":"lawyer","title":"The unwelcome settlement number","scenario":"The client hoped to settle for $200K; the realistic number is $600K. You need to deliver this without softening it into false hope. Your draft opens with a long defense of the other side's position.","task":"Write a 3-sentence message that front-loads the realistic number and why.","tips":["Lead with the number: it's $600K, not $200K.","Give the driver honestly — their damages proof is strong.","False hope now means a harder conversation later."],"focus":["clarity","precision"]},
    {"id":"hard-law-mid-08","level":"mid","profession":"lawyer","title":"Telling the client they can't do what they promised","scenario":"The client's sales VP already promised a customer something the contract can't legally deliver. You need to tell him he has to walk it back. Your draft is apologetic and buries the bottom line.","task":"Write a 2-3 sentence message that clearly states he needs to walk it back and how.","tips":["State it plainly: that promise can't stand.","Give the reason in his terms, briefly.","Offer the walk-back language so he's not stranded."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-09","level":"mid","profession":"lawyer","title":"The junior isn't ready for the deposition","scenario":"A junior asked to take a deposition solo; you don't think they're ready. You need to say no in a way that's honest about the gap but developmental, not deflating.","task":"Write a 3-sentence response that declines, names the gap honestly, and gives a path to readiness.","tips":["Say not yet, clearly.","Name the specific skill gap, not a vague 'more experience.'","Give the concrete path: second-chair the next two."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-10","level":"mid","profession":"lawyer","title":"Delivering the adverse ruling","scenario":"The court ruled against the client on the key motion. You need to tell the CEO. Your draft spends two paragraphs on how hard the team fought before the outcome. He needs the outcome first.","task":"Write a 3-sentence message: the ruling, what it means, the next step.","tips":["Bad news in sentence one, plainly.","What it means for them, concretely.","Then the path forward — you have one, so lead them to it."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-11","level":"mid","profession":"lawyer","title":"The 'no' to a friend-of-the-firm favor","scenario":"A referral source asks the firm to take on a matter that's outside your expertise and would be done badly. You need to decline without damaging the relationship. Your draft over-explains and sounds like it might yield.","task":"Write a 2-3 sentence decline that protects the relationship and stays firm.","tips":["Decline clearly but warmly.","Give the honest reason: it's not our strength.","Offer a referral to someone who is — that's the favor."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-12","level":"mid","profession":"lawyer","title":"Correcting a partner's mistake","scenario":"You spotted that the partner's draft argument relies on an overruled case. You need to flag it upward — a hard message to a superior. Your draft buries it in praise or softens it into a question.","task":"Write a 2-3 sentence message that flags the error clearly and respectfully.","tips":["State the issue plainly: that case was overruled last year.","Give the fix, not just the problem.","Respectful and direct beats hinting — she'd rather know now."],"focus":["clarity","precision"]},
    {"id":"hard-law-mid-13","level":"mid","profession":"lawyer","title":"The client's expectations on timeline","scenario":"The client thinks the case resolves in three months; realistically it's a year-plus. You need to reset this now. Your draft lists procedural steps hoping they'll infer the timeline themselves.","task":"Write a 3-sentence message that states the realistic timeline directly and why.","tips":["Give the real number: 12-18 months, not three.","One line on what drives it — discovery, the court's calendar.","Let them plan on truth, not on hope."],"focus":["clarity","precision"]},
    {"id":"hard-law-mid-14","level":"mid","profession":"lawyer","title":"Behavior-impact-ask with the difficult junior","scenario":"A junior is talented but repeatedly misses internal deadlines, forcing you to scramble. You need feedback that names the pattern, its impact on the team, and a clear ask — not a general 'work on time management.'","task":"Write feedback in behavior-impact-ask form, 3 sentences.","tips":["Behavior: name the specific missed-deadline pattern.","Impact: what it costs the team and the matter.","Ask: the concrete change and how you'll check it."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-15","level":"mid","profession":"lawyer","title":"Telling the client their key document hurts them","scenario":"In reviewing the client's files, you found an email from their own executive that badly undercuts the case. You need to deliver this hard fact clearly. Your draft circles it with reassurances first.","task":"Write a 3-sentence message that front-loads the problem document and what it means.","tips":["Name the document and the problem plainly.","State the impact on the case honestly.","Then the plan — how you'll address or contain it."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-16","level":"mid","profession":"lawyer","title":"The clean 'no' to scope creep","scenario":"The client keeps adding tasks outside the engagement without discussing fees. You need to draw the line clearly. Your draft is passive and apologetic, which invites more creep.","task":"Write a 2-3 sentence message that declines the added work under the current terms and offers the real path.","tips":["Name the added work as out of scope, plainly.","Don't apologize for having a scope.","Offer the path: a scope amendment with the fee."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-17","level":"mid","profession":"lawyer","title":"Delivering the conflict-of-interest news","scenario":"You have to tell a prospective client the firm can't represent them because of a conflict — after they've already shared their story and gotten their hopes up. This is a disappointing message to deliver clearly.","task":"Write a 3-sentence message that delivers the news clearly and helpfully.","tips":["State it directly: we can't take this on, and why.","Don't over-apologize — it's a rule, not a slight.","Point them somewhere useful: a referral."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-18","level":"mid","profession":"lawyer","title":"Telling the partner you disagree with the strategy","scenario":"The partner set a litigation strategy you believe is a mistake. You need to voice the disagreement clearly before it's locked in. Your draft softens it into vague 'considerations' she'll wave off.","task":"Write a 2-3 sentence message that states your disagreement and reasoning directly.","tips":["Say you disagree, and on what specifically.","Give the concrete reason and the alternative.","Clear dissent now beats an 'I told you so' later."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-19","level":"mid","profession":"lawyer","title":"The bad news on the appeal odds","scenario":"The client wants to appeal; you think the odds are poor — maybe 15%. You need to deliver this without either crushing them or falsely encouraging them. Your draft hedges to avoid disappointing them.","task":"Write a 3-sentence message that gives the honest odds and what they mean for the decision.","tips":["Give the number honestly: about 15%.","Frame what that means for the cost/benefit.","Honest odds respect their right to decide."],"focus":["clarity","precision"],"placeholder":"I'll be straight: the appeal is a long shot — I'd put it around 15%."},
    {"id":"hard-law-mid-20","level":"mid","profession":"lawyer","title":"Telling the business team their contract is unenforceable","scenario":"The business team spent months on a deal built on a contract clause that's legally unenforceable. You need to tell them the foundation won't hold. Your draft buries it under alternatives before the bad news.","task":"Write a 3-sentence message that front-loads the problem and pivots to the fix.","tips":["Lead with the hard truth: that clause won't hold up.","Acknowledge the work done, briefly, without cushioning the news.","Then the fix — restructure it this way."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-21","level":"mid","profession":"lawyer","title":"The feedback the junior won't want to hear","scenario":"A junior's written analysis is consistently strong on research but weak on judgment — they can't tell which issues matter. You need to name this developmental gap honestly, not paper over it in a review.","task":"Write 3 sentences of feedback that name the gap, its impact, and the development path.","tips":["Name it precisely: research is strong, prioritization isn't yet.","Impact: partners have to re-triage your memos.","Path: the concrete practice that builds the judgment."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-22","level":"mid","profession":"lawyer","title":"Declining the client's illegal-adjacent request","scenario":"The client asks you to structure a transaction in a way that skirts a regulation. You need to say no firmly — this crosses a line — without lecturing or damaging the relationship.","task":"Write a 2-3 sentence 'no' that's firm on the line and offers a compliant path.","tips":["Say no clearly — this one isn't negotiable.","State the line briefly, without moralizing.","Offer the compliant structure that gets close to their goal."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-23","level":"mid","profession":"lawyer","title":"Telling the CEO the deposition went badly","scenario":"The client's CEO gave damaging testimony in his deposition despite your prep. You need to deliver this honestly so strategy can adjust. Your draft softens it into 'some challenging moments.'","task":"Write a 3-sentence message that states the problem clearly and the strategic response.","tips":["Name the damage plainly, not 'challenging moments.'","Say specifically what he conceded and why it matters.","Then the plan to contain it — you have one."],"focus":["clarity","impact"]},
    {"id":"hard-law-mid-24","level":"mid","profession":"lawyer","title":"The hard cost conversation","scenario":"The matter will cost far more than the client budgeted to see it through, and they need to decide whether to keep going. You need to lay out the hard financial reality clearly, not sugarcoat it.","task":"Write a 3-sentence message that states the cost reality and frames the decision honestly.","tips":["Give the real remaining cost, plainly.","Frame the actual decision: invest more or resolve now.","Don't soften the number into a range that hides the truth."],"focus":["clarity","precision"]},
    {"id":"hard-law-mid-25","level":"mid","profession":"lawyer","title":"The spoken hard message on the call","scenario":"You have to tell the client on a live call that a key witness has recanted, weakening the case significantly. There's no email buffer — you have to say it clearly and steady them in real time.","task":"Script a 3-4 sentence spoken delivery: the news, its impact, and the immediate response.","tips":["Say the news plainly and early — don't bury it in preamble.","State the impact honestly.","Move to the response so they don't sit in the shock."],"focus":["clarity","impact"]}
  ],
  "putting-it-together": [
    {"id":"together-law-mid-01","level":"mid","profession":"lawyer","title":"The full settlement recommendation","scenario":"You need to send the client's GC a complete settlement recommendation: the number, the reasoning, the risk of not settling, and the ask for authority. It must lead with the recommendation, be tight, and end with a clear decision.","task":"Write the complete email in 5-6 sentences integrating recommendation, reasoning, and the ask.","tips":["Lead with the recommendation and number.","Two tight reasons, not ten.","End with the specific authority you're asking for and by when."],"focus":["structure","impact"]},
    {"id":"together-law-mid-02","level":"mid","profession":"lawyer","title":"Same news, three channels","scenario":"You need to convey an adverse ruling to the client: a formal memo for the file, a two-line text to the GC who's traveling, and talking points for the CEO's board update. Same facts, three registers.","task":"Write the two-line text version, then note how the board talking-point version would differ.","tips":["The text: outcome and next step, nothing more.","The board version adds framing and the strategic response.","Match register to channel — that's the whole skill."],"focus":["audience","concision"]},
    {"id":"together-law-mid-03","level":"mid","profession":"lawyer","title":"Editing your own memo like a reader","scenario":"You've drafted a client advice memo and it's technically complete but reads like it was written for you, not the client. You need to edit it as the busy GC who'll receive it — cutting, resequencing, clarifying.","task":"Write the 3 edits you'd make as the reader, and the revised opening sentence.","tips":["Read as the GC: what do they need in the first ten seconds?","Cut what serves your process, not their decision.","Resequence so the answer leads."],"focus":["audience","clarity"]},
    {"id":"together-law-mid-04","level":"mid","profession":"lawyer","title":"The negotiation update under time pressure","scenario":"Mid-negotiation, you have five minutes to update the client by phone before the next session: where things stand, the open term, and the decision you need from them. It must be complete, structured, and fast.","task":"Script a 4-5 sentence spoken update that covers status, the open term, and the decision needed.","tips":["Status in one line, then the single open term.","Frame the decision they must make now.","Fast and structured — they're deciding on your words."],"focus":["structure","concision"]},
    {"id":"together-law-mid-05","level":"mid","profession":"lawyer","title":"The client alert that works","scenario":"You're finalizing a client alert on a new law. It must lead with who's affected and what to do, be free of legalese, tell the story of why it matters, and end with a clear next step — all in a tight, scannable format.","task":"Write the alert's headline, opening sentence, and closing action line.","tips":["Headline names the affected reader and the action.","Opening makes them self-select in or out.","Closing gives the one concrete next step."],"focus":["audience","impact"]},
    {"id":"together-law-mid-06","level":"mid","profession":"lawyer","title":"The board briefing memo","scenario":"The GC asked for a one-page litigation briefing for the board: portfolio-level risk, the biggest matter, and the one decision needed. It must be pitched for non-lawyers, lead with the point, and stay on one page.","task":"Write the memo's opening paragraph (3-4 sentences) integrating the frame, the key matter, and the decision.","tips":["Frame the portfolio in a line — exposure and trend.","Spotlight the one matter that needs attention.","Surface the decision so the board knows why they're reading."],"focus":["audience","structure"]},
    {"id":"together-law-mid-07","level":"mid","profession":"lawyer","title":"The hard message, well delivered","scenario":"You must tell the client their case has weakened and recommend a lower settlement target — bad news plus a recommendation, in one message. It needs to front-load the news, own the recommendation, and give a clear path.","task":"Write the complete 5-sentence message integrating the hard news and the recommendation.","tips":["Front-load the news, then own the recommendation.","Keep the reasoning tight — two points.","End on the path forward and the decision needed."],"focus":["impact","clarity"]},
    {"id":"together-law-mid-08","level":"mid","profession":"lawyer","title":"Feedback that's clear and kind","scenario":"You're giving a junior end-of-matter feedback: what they did well, the one real development area, and a concrete path — integrating honesty with encouragement, structured so the development point lands and sticks.","task":"Write the 4-5 sentence feedback integrating the strength, the growth area, and the path.","tips":["Genuine strength first, specifically.","One growth area, named as behavior-impact.","Concrete path so it's development, not just critique."],"focus":["clarity","impact"]},
    {"id":"together-law-mid-09","level":"mid","profession":"lawyer","title":"The compliance answer for the business team","scenario":"The business team asks whether they can proceed with a marketing campaign. Your complete answer needs the verdict, the conditions, the plain-language reason, and the escalation path — all pitched for non-lawyers and tightly organized.","task":"Write the complete 4-5 sentence answer integrating verdict, conditions, and escalation.","tips":["Yes/no verdict first.","Conditions as a scannable short list.","Plain language throughout, plus who to ask on edge cases."],"focus":["audience","structure"]},
    {"id":"together-law-mid-10","level":"mid","profession":"lawyer","title":"The matter-status email, edited","scenario":"Your weekly status email to the client is complete but bloated — chronological, hedged, and burying the one thing that needs their attention. You need to rewrite it as a tight, reader-first update.","task":"Rewrite it as a 4-sentence update: the headline, status, the one item needing attention, next step.","tips":["Lead with what changed, not the chronology.","One line of status, cleanly.","Surface the item needing a decision — don't bury it."],"focus":["structure","concision"]},
    {"id":"together-law-mid-11","level":"mid","profession":"lawyer","title":"The demand letter, complete","scenario":"You're finalizing a demand letter that must tell the story of the breach, state the legal basis, make a clear demand, set a deadline, and read firm-but-professional for the double audience of opposing counsel and a future judge.","task":"Write the letter's opening (story, 3 sentences) and the closing (demand and deadline, 2 sentences).","tips":["Open with the human narrative of the breach.","Close with a specific demand and hard deadline.","Firm and factual for both readers — no adjectives."],"focus":["impact","precision"]},
    {"id":"together-law-mid-12","level":"mid","profession":"lawyer","title":"The tough call, fully handled","scenario":"On a live client call, you must deliver an adverse development, absorb the reaction, answer the CEO's pointed follow-up honestly, and close with a clear next step — integrating hard-message delivery, pressure handling, and structure.","task":"Script the 5-6 sentence arc: deliver, steady, answer the likely follow-up, close.","tips":["Deliver the news plainly, then steady the room.","Answer the predictable follow-up directly.","Close on the next step so it ends with a plan."],"focus":["impact","structure"]},
    {"id":"together-law-mid-13","level":"mid","profession":"lawyer","title":"The fee conversation, complete","scenario":"You must tell the client the matter will cost more than budgeted, explain why, own the recommendation to continue, and give them a real decision — integrating precision, hard-message delivery, and a clear ask.","task":"Write the complete 5-sentence message integrating the number, the reason, and the decision.","tips":["Lead with the revised number, plainly.","One clear reason tied to what changed.","Frame the honest decision and recommend a path."],"focus":["precision","impact"]},
    {"id":"together-law-mid-14","level":"mid","profession":"lawyer","title":"The advice memo, reader-first","scenario":"You're writing a full advice memo answering whether the client can terminate a key vendor. It must lead with the answer, structure the conditions, use plain language, and be tight enough that a busy executive reads it in one pass.","task":"Write the memo's opening paragraph (4 sentences): answer, key conditions, and what to do next.","tips":["Answer the question asked in sentence one.","Conditions structured, not buried in prose.","End with the concrete next action."],"focus":["structure","audience"]},
    {"id":"together-law-mid-15","level":"mid","profession":"lawyer","title":"The persuasive settlement memo","scenario":"You're writing a memo to persuade a reluctant client to settle. It must frame the before/after, pre-empt their cost objection, own the recommendation, and stay tight — integrating narrative, presence, and structure.","task":"Write the memo's 5-sentence core integrating the frame, the pre-empted objection, and the recommendation.","tips":["Open with the before/after frame.","Pre-empt the strongest objection in a line.","Own the recommendation and close on the decision."],"focus":["impact","structure"]},
    {"id":"together-law-mid-16","level":"mid","profession":"lawyer","title":"Translating for the deputy GC vs. the CEO","scenario":"You need to convey the same litigation risk to two readers: the deputy GC (a lawyer who wants the legal nuance) and the CEO (who wants the business impact). Same facts, two altitudes and two registers.","task":"Write the one-sentence version for each reader, showing the altitude difference.","tips":["Deputy GC: the legal hinge and your call on it.","CEO: the business exposure and whether it threatens plans.","Same truth, calibrated to what each will do with it."],"focus":["audience","precision"]},
    {"id":"together-law-mid-17","level":"mid","profession":"lawyer","title":"The negotiation prep brief, complete","scenario":"You're preparing the client for a contract negotiation. The brief must structure the terms by priority, own your recommended positions, quantify the tradeoffs, and read as a clear decision map for the client at the table.","task":"Write the brief's opening structure: the tier framing plus your recommended stance on the top term.","tips":["Three tiers — must-have, tradeable, give-away.","Own a recommended position on each, don't just list.","Quantify the top tradeoff so the client can decide fast."],"focus":["structure","impact"]},
    {"id":"together-law-mid-18","level":"mid","profession":"lawyer","title":"The under-pressure board answer, complete","scenario":"At a board meeting, a director asks an unexpected question about overall legal exposure. You must answer the actual question, give an honest read with the right precision, structure it, and offer a proper follow-up — all composed and on the spot.","task":"Script the 4-sentence answer: the direct read, the precision caveat, and the follow-up offer.","tips":["Answer the actual question first, at a high level.","Give the honest read with an appropriate range.","Offer the detailed follow-up rather than winging specifics."],"focus":["impact","structure"]},
    {"id":"together-law-mid-19","level":"mid","profession":"lawyer","title":"The client-onboarding note","scenario":"A first-time litigation client is confused about what happens next and what it costs. Your note must translate the process into their world, structure the next 90 days, be tight, and end with the one decision they'll face soonest.","task":"Write the complete 4-5 sentence note integrating the plain-language process, the cost, and the first decision.","tips":["Walk their next 90 days, not the litigation lifecycle.","Money in plain terms — estimated versus as-billed.","Name the soonest decision so they know what's coming."],"focus":["audience","clarity"]},
    {"id":"together-law-mid-20","level":"mid","profession":"lawyer","title":"The escalation to the partner","scenario":"You need to escalate a matter risk to the supervising partner: the situation, the complication, your recommended response, and the decision you need — integrating SCQA structure, precision, and presence in a tight message.","task":"Write the complete 5-sentence escalation using SCQA plus your recommendation.","tips":["Situation and complication set it up fast.","Question then your recommended answer.","End with the specific decision or approval needed."],"focus":["structure","impact"]},
    {"id":"together-law-mid-21","level":"mid","profession":"lawyer","title":"The 30-second elevator update","scenario":"The relationship partner catches you in the elevator: \"How's the whole Aldrin portfolio?\" You have 30 seconds to give a complete, structured, decision-relevant answer across three matters — leading with the point, precise, and calm.","task":"Script the 30-second spoken answer: portfolio headline, the one mover, the decision if any.","tips":["Headline the portfolio in a line.","Spotlight the one thing that changed.","Flag any decision, then stop — 30 seconds is the discipline."],"focus":["concision","structure"]},
    {"id":"together-law-mid-22","level":"mid","profession":"lawyer","title":"The redline explanation for two audiences","scenario":"You've redlined a contract and must explain your key changes twice: a technical note to the junior on why, and a plain-language summary to the business team on what it means for them. Same changes, two registers.","task":"Write the one-line business-team version and the one-line junior version of the same key change.","tips":["Business team: what the change protects them from.","Junior: the principle and failure mode behind the change.","One truth, two altitudes — the core skill."],"focus":["audience","clarity"]},
    {"id":"together-law-mid-23","level":"mid","profession":"lawyer","title":"The complete matter close-out","scenario":"A matter has resolved and you're writing the close-out to the client: the outcome, what it means, lessons for next time, and the relationship-preserving close — integrating clarity, structure, and register.","task":"Write the complete 4-5 sentence close-out integrating outcome, meaning, and forward note.","tips":["Lead with the outcome, plainly.","State what it means for them going forward.","Close with a forward-looking note that keeps the relationship warm."],"focus":["structure","audience"]},
    {"id":"together-law-mid-24","level":"mid","profession":"lawyer","title":"The disagreement with the partner, complete","scenario":"You need to tell the partner you disagree with her chosen strategy, back it with reasoning, propose an alternative, and stay respectful — integrating hard-message delivery, presence, and structure in one message she'll actually weigh.","task":"Write the complete 4-5 sentence message integrating the disagreement, the reasoning, and the alternative.","tips":["State the disagreement clearly and respectfully.","Give the concrete reason, not a vague worry.","Propose the alternative so it's constructive, not just dissent."],"focus":["impact","clarity"]},
    {"id":"together-law-mid-25","level":"mid","profession":"lawyer","title":"The capstone client counseling call","scenario":"You're counseling the client through a major decision — settle or proceed to trial — on a call. You must frame the choice, give your recommendation, handle their pushback, deliver the honest risk, and land on a clear decision, all live.","task":"Script the 6-sentence arc: frame the choice, recommend, pre-empt one objection, state the risk, close on the decision.","tips":["Frame the real choice cleanly, then own your recommendation.","Pre-empt their likely objection in a line.","Deliver the honest risk and close by asking for the decision."],"focus":["structure","impact"]}
  ],
};
